/**
 * US-DOSSIER-001c — the story dossier page
 * (`.roll/features/<epic>/<ID>/index.html`, regenerated by `roll index`).
 *
 * One story, five stations: Definition (the wish, quoted from spec.md) →
 * Design (spec bullets) → Execution (TCR commits, when the caller supplies
 * them) → Delivery (attest banner + AC table from ac-map.json) →
 * Retrospective (Review Score note). Every figure on the page is computed from
 * the real card folder — spec.md / ac-map.json / latest/ — never typed in.
 *
 * Coexistence with story-page.ts: renderStoryPage() mints the INITIAL
 * skeleton when a card is born (roll idea / migrate) and markPhaseDone()
 * advances it mid-flight; this renderer REBUILDS the page from data when
 * `roll index` sweeps. Both wear the same chrome; the dossier is the
 * data-complete form.
 */
import { CHROME_CONTROLS, CHROME_CSS, CHROME_SCRIPT, bi, buildExecutionCastProjection, type ExecutionCastRow } from "@roll/core";
import { resolveIntegrationBranch } from "@roll/infra";
import { type CycleRoleSummary, type CycleRoleName, type CycleRoleAttemptState, type DeliveryLadder, parseEventLine, type StoryEvidenceFlags, type BrowserOperationsTruth, type BrowserOperationsTimeline } from "@roll/spec";
import { execFileSync } from "node:child_process";
import { existsSync, readdirSync, readFileSync, statSync } from "node:fs";
import { join as joinPath, relative as relativePath, resolve as resolvePath, sep } from "node:path";
import { type DossierStory } from "./archive.js";
import { rowDelivered } from "./truth-adapter.js";
import { collectBrowserTruth } from "./browser-truth-collect.js";
import { collectBrowserTimeline } from "./browser-timeline-collect.js";
import { renderBrowserOperationsTimelineHtml } from "./browser-ops-timeline.js";
import { DOSSIER_CSS } from "./dossier-css.js";
import { SPINE_STAGES, deriveDeliveryLadder } from "./dossier-index.js";
import { readLatestStoryReviewScore, readReviewScoreTrend, type ReviewScoreView } from "./review-score.js";
import { phaseSectionTag } from "./story-page.js";

const esc = (s: string): string =>
  s.replace(/&/g, "&amp;").replace(/</g, "&lt;").replace(/>/g, "&gt;").replace(/"/g, "&quot;");

/** US-DOSSIER-024: one piece of inline evidence attached to an AC. `screenshot`
 *  is real-pixel proof (renders a thumbnail); `text` is inline file content. */
export interface AcEvidence {
  kind: "screenshot" | "text" | "cast" | "video";
  label?: string;
  /** Relative href to the artifact (screenshot/cast/video or a text file). */
  href?: string;
  /** FIX-285: story-page-safe text evidence body, read from the card folder. */
  textContent?: string;
  /** FIX-285: honest empty state when a text evidence file cannot be read. */
  textError?: "missing";
}

/** US-DOSSIER-024: whether an AC is "observable" (visual/interactive UI — needs a
 *  real screenshot/cast to attest) or "readonly" (doc/contract — may attest on
 *  text evidence). Derived from ac-map evidence kinds, else a copy heuristic. */
export type AcKind = "observable" | "readonly";

/** One AC row as read from ac-map.json (001d wires the file in). */
export interface AcRow {
  ac: string;
  status: string;
  note?: string;
  /** EVID-010: a re-runnable command that independently verifies this AC. */
  verify?: string;
  /** EVID-010: test files/cases covering this AC. */
  tests?: string[];
  /** US-DOSSIER-024: the ac-map `evidence[]` entries (screenshot / text / cast). */
  evidence?: AcEvidence[];
}

export interface ExecutionRef {
  kind: "merged-pr" | "cycle" | "pre-evidence";
  label: string;
  commitCount?: number;
}

export type CiVerdict = "green" | "red" | "none";

export interface DeliveryPrEvidence {
  number: number;
  href?: string;
  ci?: CiVerdict;
}

export interface DeliveryCostEvidence {
  usd?: number;
  tokensIn?: number;
  tokensOut?: number;
}

export interface DeliveryTimelineEntry {
  label: string;
  at: string;
}

export interface CorrectionTraceEntry {
  action: string;
  signal: string;
  reason: string;
  at: string;
  mode?: string;
  source?: string;
  targetId?: string;
}

export type PeerReviewVerdict = "AGREE" | "REFINE" | "OBJECT" | "ESCALATE";

export interface PeerReviewRound {
  round: number;
  verdict: PeerReviewVerdict;
  peer?: string;
  stage?: string;
  findings: string[];
  href?: string;
}

export interface PeerReviewEvidence {
  finalVerdict: PeerReviewVerdict;
  rounds: PeerReviewRound[];
}

export interface DynamicEvidence {
  kind: "cast" | "video";
  label: string;
  href: string;
}

export interface StoryGraphLink {
  id: string;
  href?: string;
}

export interface StoryReleaseTrace {
  label: string;
  href?: string;
}

export interface StoryGraph {
  dependsOn?: StoryGraphLink[];
  dependedBy?: StoryGraphLink[];
  fixes?: StoryGraphLink[];
  release?: StoryReleaseTrace;
}

export interface DeliveryEvidence {
  prs?: DeliveryPrEvidence[];
  diffHref?: string;
  filesChanged?: string[];
  agent?: string;
  cost?: DeliveryCostEvidence;
  timeline?: DeliveryTimelineEntry[];
}

/** Everything the dossier needs beyond the 001a story model. */
export interface StoryDossierInput {
  story: DossierStory;
  /** The story primitive parsed from spec.md (US-DOSSIER-003). */
  narrative?: { asA?: string; iWant?: string; soThat?: string };
  /** Domain Model Context line, e.g. "Acceptance Evidence" (US-DOSSIER-003). */
  context?: string;
  /** AC checklist items parsed from the spec's `**AC:**` block (US-DOSSIER-003). */
  acItems?: { text: string; checked: boolean }[];
  /** First blockquote / lede paragraph of spec.md — the wish (fallback). */
  wish?: string;
  /** Spec bullets under a 方案/Solution/Design heading. */
  design?: string[];
  /** TCR commit subjects touching this story (oldest first). */
  commits?: string[];
  /** PR/cycle evidence that proves execution even when squash removed TCR commit subjects. */
  executionRefs?: ExecutionRef[];
  /** Parsed ac-map.json rows. */
  acRows?: AcRow[];
  /** Relative href to the attest report (when latest/ carries one). */
  reportHref?: string;
  /** Reconstructable delivery facts: PR/CI/diff/agent/cost/timeline. */
  deliveryEvidence?: DeliveryEvidence;
  /** US-EVID-012: optional cast/video replay artifacts from the latest run. */
  dynamicEvidence?: DynamicEvidence[];
  /** US-EVID-011: peer-review decisions captured from runtime pairing records. */
  peerReview?: PeerReviewEvidence;
  /** US-EVID-009: traversable inter-story graph and release trace. */
  storyGraph?: StoryGraph;
  /** US-EVID-014: traceable automatic correction decisions for this story. */
  correctionActions?: CorrectionTraceEntry[];
  /** Retrospective text (Review Score note body). */
  retro?: string;
  /** Structured latest Review Score note for the retrospective station. */
  reviewScore?: ReviewScoreView;
  /** US-SKILL-014 trend line, merged from card-local and legacy notes. */
  reviewScoreTrend?: string;
  /** US-DOSSIER-023: the claimed→merged→attested rung this story reached, derived
   *  from the SAME signals `deriveDeliveryLadder` folds (backlog ✅ Done claim +
   *  FIX-278 merge truth via `story.delivered` + ac-map/report/screenshot evidence).
   *  Set by `collectStoryDossierInput`; absent for ad-hoc inputs, in which case
   *  the renderer derives it from `story` + `evidence`. */
  ladder?: DeliveryLadder | "none";
  /** US-DOSSIER-023: the on-disk evidence presence flags backing the `attested`
   *  rung (report / ac-map / real-pixel screenshot). */
  evidence?: StoryEvidenceFlags;
  /** US-DOSSIER-024: real image files under `latest/screenshots` (relative
   *  hrefs). Backs the per-AC evidence thumbnail + observable-gap detection so
   *  an observable AC with captured pixels is never falsely flagged a gap. */
  screenshotFiles?: string[];
  /** US-OBS-034 — cycle role summary (Execution Cast) for the dossier page. */
  cycleRoleSummary?: CycleRoleSummary;
  /** Relative href from the story dossier root to `summary.json`. */
  cycleRoleSummaryHref?: string;
  /** Hrefs keyed by CycleRoleAttempt artifact/log paths. */
  cycleRoleArtifactHrefs?: Record<string, string>;
  /** US-BROW-009b: truth-adapter browser readiness for this story. */
  browserTruth?: BrowserOperationsTruth;
  /** US-BROW-013: compact timeline projected from declared browser facts. */
  browserTimeline?: BrowserOperationsTimeline;
  /** US-BROW-013: authorized artifact hrefs for timeline diagnostic/capture links. */
  browserTimelineArtifactHrefs?: Record<string, string>;
}

/**
 * US-DOSSIER-023 — the delivery-node state on the lifecycle spine. The binary
 * delivered model becomes three honest rungs (the design reference's truth model):
 *   - `claimed`  — backlog says ✅ Done but main carries no merge evidence yet
 *     (a wish recorded, not yet truth). Hatched/hollow node.
 *   - `merged`   — merge truth on main (FIX-278) but the AC evidence chain is not
 *     yet complete — the honest middle rung, attest-pending teal, never full green.
 *   - `attested` — merged AND every attest artifact present (report + ac-map +
 *     a real-pixel screenshot). Truth-green.
 *   - `none`     — not even claimed Done; the delivery node stays empty.
 * Derived deterministically from the same truth sources the ladder uses; the
 * renderer prefers a pre-derived `d.ladder` and otherwise recomputes it locally
 * from `d.story` + `d.evidence` so a missing source never fakes progress.
 */
export function storyDeliveryState(d: StoryDossierInput): DeliveryLadder | "none" {
  if (d.ladder !== undefined) return d.ladder;
  const evidence: StoryEvidenceFlags = d.evidence ?? { report: false, acMap: false, visualEvidence: false };
  // The same derivation `deriveDeliveryLadder` performs, but tolerant of ad-hoc
  // inputs: a `delivered:true` story with no live evidence flags still falls back
  // to the honest `merged` rung (never silently `attested`).
  return deriveDeliveryLadder({ delivered: d.story.delivered, status: d.story.status }, evidence);
}

/** Which stations are complete, derived from the data we actually have. */
export function stationsDone(d: StoryDossierInput): Set<string> {
  const done = new Set<string>(["definition"]); // a card existing IS the definition
  if ((d.design?.length ?? 0) > 0 || d.peerReview !== undefined) done.add("design");
  if ((d.commits?.length ?? 0) > 0 || (d.executionRefs?.length ?? 0) > 0) done.add("execution");
  if (d.story.delivered) done.add("delivery");
  if (d.reviewScore !== undefined || (d.retro !== undefined && d.retro !== "")) done.add("retrospective");
  return done;
}

/**
 * US-DOSSIER-023: the full lifecycle spine, with the delivery node refined into
 * the three-rung claimed→merged→attested ladder (the design reference's truth
 * model) instead of the old binary truth/empty:
 *   - `.node.claimed`  — backlog ✅ Done, no merge evidence yet → hatched/hollow
 *     (a wish recorded, not yet truth); the delivery node is reached-but-unproven.
 *   - `.node.merged`   — merge truth on main but attest chain incomplete →
 *     solid attest-pending teal, the honest middle rung, never full green.
 *   - `.node.attested` — merged AND full attest evidence → solid truth-green.
 * Upstream lifecycle stations (definition…execution, retrospective) keep their
 * `.node.done` accent; legacy cards keep the uniform muted spine (US-DOSSIER-008).
 */
export function storySpine(d: StoryDossierInput): string {
  // US-DOSSIER-008: a pre-v3 legacy delivery has no v3 evidence trail; the
  // evidence-derived spine would read as half-finished, so render the whole
  // spine in a uniform muted "legacy" state instead. The three-state ladder
  // never touches legacy cards — they honestly show no v3 progress.
  if (d.story.legacy) {
    const nodes = SPINE_STAGES.map((s, i) => {
      const seg = i < SPINE_STAGES.length - 1 ? `<span class="seg"></span>` : "";
      return `<span class="node legacy"><span class="dot"></span><span class="tag">${bi(s.en, s.zh)}</span></span>${seg}`;
    });
    return `<div class="spine legacy" title="历史交付 · pre-v3，无 v3 留痕">${nodes.join("")}</div>`;
  }
  const done = stationsDone(d);
  // US-DOSSIER-023: the delivery node's state is the ladder rung, not a binary.
  // `claimed` is reached-but-unproven (backlog Done, no merge) — it lights the
  // node hatched even though `stationsDone` (gated on merge truth) excludes it.
  const ladder = storyDeliveryState(d);
  const deliveryCls =
    ladder === "attested" ? "attested" : ladder === "merged" ? "merged" : ladder === "claimed" ? "claimed" : "";
  const deliveryReached = ladder !== "none";
  const nodeReached = (key: string): boolean => (key === "delivery" ? deliveryReached : done.has(key));
  const nodes = SPINE_STAGES.map((s, i) => {
    const cls = s.key === "delivery" ? (deliveryCls !== "" ? ` ${deliveryCls}` : "") : done.has(s.key) ? " done" : "";
    const next = SPINE_STAGES[i + 1];
    const segDone = nodeReached(s.key) && next !== undefined && nodeReached(next.key);
    const seg = i < SPINE_STAGES.length - 1 ? `<span class="seg${segDone ? " done" : ""}"></span>` : "";
    return `<span class="node${cls}"><span class="dot"></span><span class="tag">${bi(s.en, s.zh)}</span></span>${seg}`;
  });
  return `<div class="spine">${nodes.join("")}</div>`;
}

const AC_BADGE: Record<string, [string, string]> = {
  pass: ["✓ pass", "✓ 通过"],
  readonly: ["◆ readonly", "◆ 只读"],
  partial: ["◑ partial", "◑ 部分"],
  fail: ["✗ fail", "✗ 失败"],
  blocked: ["■ blocked", "■ 受阻"],
  claimed: ["△ claimed", "△ 仅声称"],
  missing: ["○ missing", "○ 缺失"],
};

// US-DOSSIER-024 — the AC-block status colors align with the three-state spine
// ladder (US-DOSSIER-023). `attested` statuses → truth-green; `merged`/pending
// → attest-pending teal; `claimed`/gap → claim amber; failures → drift red.
const AC_STATE: Record<string, "attested" | "merged" | "claimed" | "fail" | "muted"> = {
  pass: "attested",
  readonly: "attested",
  partial: "merged",
  claimed: "claimed",
  missing: "muted",
  fail: "fail",
  blocked: "fail",
};
const AC_STATE_COLOR: Record<"attested" | "merged" | "claimed" | "fail" | "muted" | "gap", string> = {
  attested: "#178a52",
  merged: "#0d9488",
  claimed: "#c77d12",
  gap: "#c77d12",
  fail: "#d23b3b",
  muted: "#9aa3b2",
};

// US-DOSSIER-024 — heuristic when ac-map carries no screenshot/cast evidence to
// settle the class: AC copy that names a visual/interactive surface (render,
// screenshot, UI, page, panel, banner, badge, chip, button, click, hover, tab,
// 渲染/截图/界面/页面/面板/徽标/点击) is OBSERVABLE; otherwise READONLY (doc/contract).
const OBSERVABLE_RE =
  /\b(render|renders|rendered|screenshot|screencast|cast|recording|video|visual|UI|GUI|page|panel|banner|badge|chip|button|click|clicks|hover|tab|tabs|spine|ladder|thumbnail|pixel|layout|component|surface|dashboard|console)\b|渲染|截图|截屏|录屏|界面|页面|面板|徽标|芯片|按钮|点击|悬停|布局|组件|可视|可观测|缩略/i;
const READONLY_RE = /\b(readonly|read-only|doc|docs|document|contract|schema|spec|config|exit code|stdout|invariant)\b|只读|文档|契约|口径|不变量|退出码/i;

/**
 * US-DOSSIER-024 — classify an AC as observable (visual/interactive UI, needs a
 * real screenshot/cast to attest) vs readonly (doc/contract, may attest on text).
 * Priority: ac-map evidence kinds (a screenshot/cast/video entry ⇒ observable;
 * only-text evidence + `readonly` status ⇒ readonly) → the AC-copy heuristic.
 */
export function classifyAc(row: AcRow): AcKind {
  const ev = row.evidence ?? [];
  if (ev.some((e) => e.kind === "screenshot" || e.kind === "cast" || e.kind === "video")) return "observable";
  if (row.status === "readonly") return "readonly";
  const text = `${row.ac} ${row.note ?? ""}`;
  if (READONLY_RE.test(text) && !OBSERVABLE_RE.test(text)) return "readonly";
  if (OBSERVABLE_RE.test(text)) return "observable";
  // Evidence is only text and copy is ambiguous → treat as readonly (doc/contract).
  if (ev.length > 0 && ev.every((e) => e.kind === "text")) return "readonly";
  return "readonly";
}

/** US-DOSSIER-024 — does this AC carry a real pixel/dynamic artifact (a
 *  screenshot/cast/video evidence entry) under its ac-map evidence list, OR a
 *  matching screenshot file on disk under `latest/screenshots`? */
export function acHasVisualEvidence(row: AcRow, screenshotFiles: readonly string[]): boolean {
  const ev = row.evidence ?? [];
  if (ev.some((e) => (e.kind === "screenshot" || e.kind === "cast" || e.kind === "video") && e.href !== undefined && e.href !== "")) {
    return true;
  }
  // Fall back to any real file under latest/screenshots — an observable AC is
  // backed when the run captured pixels even if ac-map didn't enumerate them.
  return screenshotFiles.length > 0;
}

/**
 * US-DOSSIER-024 — the honest, never-faking per-AC display state. An OBSERVABLE
 * AC with no real screenshot/cast (FIX-258 truth) is DEMOTED to a `gap` state —
 * it can never render as attested even when ac-map claims `pass`. READONLY ACs
 * keep their declared state (they may attest on doc/text evidence).
 */
export function acDisplayState(
  row: AcRow,
  kind: AcKind,
  screenshotFiles: readonly string[],
): "attested" | "merged" | "claimed" | "fail" | "muted" | "gap" {
  const declared = AC_STATE[row.status] ?? "muted";
  if (kind === "observable" && !acHasVisualEvidence(row, screenshotFiles)) return "gap";
  return declared;
}

function executionSummary(refs: readonly ExecutionRef[]): [string, string] {
  const mergedPrs = refs.filter((r) => r.kind === "merged-pr").length;
  if (mergedPrs > 0) return [`${mergedPrs} merged PR${mergedPrs === 1 ? "" : "s"}`, `${mergedPrs} 个已合 PR`];
  const cycles = refs.filter((r) => r.kind === "cycle").length;
  if (cycles > 0) return [`${cycles} delivery cycle${cycles === 1 ? "" : "s"}`, `${cycles} 个交付周期`];
  return ["pre-evidence history", "证据纪律前历史卡"];
}

function executionRefsHtml(refs: readonly ExecutionRef[]): string {
  if (refs.length === 0) return "";
  const [en, zh] = executionSummary(refs);
  return (
    `<p>${bi(en, zh)}</p>` +
    `<ul class="muted">${refs
      .map((r) => {
        const count =
          r.commitCount !== undefined && Number.isFinite(r.commitCount)
            ? ` · ${bi(`${r.commitCount} commits`, `${r.commitCount} 个提交`)}`
            : "";
        return `<li><code>${esc(r.label)}</code>${count}</li>`;
      })
      .join("")}</ul>`
  );
}

function hasDeliveryEvidence(e: DeliveryEvidence | undefined): boolean {
  if (e === undefined) return false;
  return (
    (e.prs?.length ?? 0) > 0 ||
    (e.filesChanged?.length ?? 0) > 0 ||
    (e.timeline?.length ?? 0) > 0 ||
    e.diffHref !== undefined ||
    e.agent !== undefined ||
    e.cost !== undefined
  );
}

function hasDynamicEvidence(items: readonly DynamicEvidence[] | undefined): boolean {
  return items !== undefined && items.length > 0;
}

function hasStoryGraph(graph: StoryGraph | undefined): boolean {
  if (graph === undefined) return false;
  return (
    (graph.dependsOn?.length ?? 0) > 0 ||
    (graph.dependedBy?.length ?? 0) > 0 ||
    (graph.fixes?.length ?? 0) > 0 ||
    graph.release !== undefined
  );
}

function ciText(v: CiVerdict | undefined): [string, string] {
  if (v === "green") return ["CI green", "CI 通过"];
  if (v === "red") return ["CI red", "CI 失败"];
  if (v === "none") return ["CI none", "无 CI"];
  return ["CI —", "CI —"];
}

function fmtTokens(n: number): string {
  if (!Number.isFinite(n)) return "—";
  if (Math.abs(n) >= 1000) return `${(n / 1000).toFixed(1).replace(/\.0$/, "")}k`;
  return String(Math.round(n));
}

function deliveryCostHtml(cost: DeliveryCostEvidence): string {
  const parts: string[] = [];
  if (cost.usd !== undefined && Number.isFinite(cost.usd)) parts.push(`$${cost.usd.toFixed(2)}`);
  if (cost.tokensIn !== undefined && Number.isFinite(cost.tokensIn)) parts.push(`${fmtTokens(cost.tokensIn)} in`);
  if (cost.tokensOut !== undefined && Number.isFinite(cost.tokensOut)) parts.push(`${fmtTokens(cost.tokensOut)} out`);
  return parts.length > 0 ? parts.map(esc).join(" · ") : "—";
}

function deliveryEvidenceHtml(e: DeliveryEvidence | undefined): string {
  if (!hasDeliveryEvidence(e) || e === undefined) return "";
  const rows: string[] = [];
  if ((e.prs?.length ?? 0) > 0) {
    const prs = (e.prs ?? [])
      .map((p) => {
        const label = `PR #${p.number}`;
        const link = p.href !== undefined ? `<a href="${esc(p.href)}">${esc(label)}</a>` : `<code>${esc(label)}</code>`;
        const [ciEn, ciZh] = ciText(p.ci);
        return `${link} <span class="pill ${p.ci === "green" ? "merged" : p.ci === "red" ? "cycle" : "backlog"}">${bi(ciEn, ciZh)}</span>`;
      })
      .join(" · ");
    rows.push(`<dt>${bi("Merged PR", "合并 PR")}</dt><dd>${prs}</dd>`);
  }
  if (e.diffHref !== undefined) {
    rows.push(`<dt>${bi("Diff", "Diff")}</dt><dd><a href="${esc(e.diffHref)}">${bi("Changed diff", "改动 diff")}</a></dd>`);
  }
  if ((e.filesChanged?.length ?? 0) > 0) {
    rows.push(
      `<dt>${bi("Files changed", "改动文件")}</dt><dd><ul class="delivery-files">${(e.filesChanged ?? [])
        .map((f) => `<li><code>${esc(f)}</code></li>`)
        .join("")}</ul></dd>`,
    );
  }
  if (e.agent !== undefined) rows.push(`<dt>${bi("Agent", "交付 agent")}</dt><dd><code>${esc(e.agent)}</code></dd>`);
  if (e.cost !== undefined) rows.push(`<dt>${bi("Cost", "成本")}</dt><dd>${deliveryCostHtml(e.cost)}</dd>`);
  if ((e.timeline?.length ?? 0) > 0) {
    rows.push(
      `<dt>${bi("Timeline", "时间线")}</dt><dd><ol class="delivery-timeline">${(e.timeline ?? [])
        .map((t) => `<li><code>${esc(t.at)}</code> ${esc(t.label)}</li>`)
        .join("")}</ol></dd>`,
    );
  }
  return `<div class="delivery-evidence"><h3>${bi("Delivery evidence", "交付证据")}</h3><dl>${rows.join("")}</dl></div>`;
}

function dynamicEvidenceHtml(items: readonly DynamicEvidence[] | undefined): string {
  if (!hasDynamicEvidence(items)) return "";
  const body = (items ?? [])
    .map((it) => {
      if (it.kind === "cast") {
        return `<li><a href="${esc(it.href)}">${esc(it.label)}</a> <span class="muted">cast</span></li>`;
      }
      const media = /\.(mp4|webm|mov)$/i.test(it.href)
        ? `<video controls preload="metadata" src="${esc(it.href)}"></video>`
        : `<a href="${esc(it.href)}">${esc(it.label)}</a>`;
      return `<li>${media}<p class="muted">${esc(it.label)}</p></li>`;
    })
    .join("");
  return `<div class="dynamic-evidence"><h3>${bi("Dynamic replay", "动态复现")}</h3><ul>${body}</ul></div>`;
}

function storyGraphLinkHtml(link: StoryGraphLink): string {
  const label = `<code>${esc(link.id)}</code>`;
  return link.href !== undefined ? `<a href="${esc(link.href)}">${label}</a>` : label;
}

function storyGraphLinksHtml(items: readonly StoryGraphLink[]): string {
  return `<ul class="graph-links">${items.map((item) => `<li>${storyGraphLinkHtml(item)}</li>`).join("")}</ul>`;
}

function storyGraphHtml(graph: StoryGraph | undefined): string {
  if (!hasStoryGraph(graph) || graph === undefined) return "";
  const rows: string[] = [];
  if ((graph.dependsOn?.length ?? 0) > 0) {
    rows.push(`<dt>${bi("Depends on", "依赖")}</dt><dd>${storyGraphLinksHtml(graph.dependsOn ?? [])}</dd>`);
  }
  if ((graph.dependedBy?.length ?? 0) > 0) {
    rows.push(`<dt>${bi("Depended by", "被依赖")}</dt><dd>${storyGraphLinksHtml(graph.dependedBy ?? [])}</dd>`);
  }
  if ((graph.fixes?.length ?? 0) > 0) {
    rows.push(`<dt>${bi("Fixes", "修复")}</dt><dd>${storyGraphLinksHtml(graph.fixes ?? [])}</dd>`);
  }
  if (graph.release !== undefined) {
    const label = `<code>${esc(graph.release.label)}</code>`;
    const release = graph.release.href !== undefined ? `<a href="${esc(graph.release.href)}">${label}</a>` : label;
    rows.push(`<dt>${bi("Release", "发版")}</dt><dd>${release}</dd>`);
  }
  return (
    `<section class="phase phase-done story-graph">` +
    `<h2>${bi("Story graph", "故事图谱")}</h2>` +
    `<dl>${rows.join("")}</dl>` +
    `</section>`
  );
}

function correctionTraceHtml(actions: readonly CorrectionTraceEntry[] | undefined): string {
  if (actions === undefined || actions.length === 0) return "";
  return `<ul class="correction-trace">${actions
    .map((a) => {
      const target = a.targetId !== undefined ? ` · <code>${esc(a.targetId)}</code>` : "";
      const mode = a.mode !== undefined ? ` · <code>${esc(a.mode)}</code>` : "";
      const source = a.source !== undefined ? ` · <code>${esc(a.source)}</code>` : "";
      return `<li><p><code>${esc(a.action)}</code> <b>${esc(a.signal)}</b>${target}${mode}${source}</p><p class="muted"><code>${esc(a.at)}</code> ${esc(a.reason)}</p></li>`;
    })
    .join("")}</ul>`;
}

function peerReviewHtml(review: PeerReviewEvidence | undefined): string {
  if (review === undefined || review.rounds.length === 0) return "";
  const rounds = review.rounds
    .map((r) => {
      const peer = r.peer !== undefined ? ` · <code>${esc(r.peer)}</code>` : "";
      const stage = r.stage !== undefined ? ` · <code>${esc(r.stage)}</code>` : "";
      const link = r.href !== undefined ? ` · <a href="${esc(r.href)}">${bi("Full record", "完整记录")}</a>` : "";
      const findings =
        r.findings.length > 0
          ? `<ul>${r.findings.map((f) => `<li>${esc(f)}</li>`).join("")}</ul>`
          : `<p class="muted">${bi("No inline findings recorded", "未记录内联意见")}</p>`;
      return (
        `<li><p><span class="peer-verdict peer-${esc(r.verdict.toLowerCase())}">${esc(r.verdict)}</span> ` +
        `${bi(`Round ${r.round}`, `第 ${r.round} 轮`)}${peer}${stage}${link}</p>${findings}</li>`
      );
    })
    .join("");
  return (
    `<div class="peer-review">` +
    `<h3>${bi("Peer review", "同行评审")}</h3>` +
    `<p><span class="peer-verdict peer-${esc(review.finalVerdict.toLowerCase())}">${esc(review.finalVerdict)}</span> ` +
    `${bi(`${review.rounds.length} rounds`, `${review.rounds.length} 轮`)}</p>` +
    `<ol>${rounds}</ol>` +
    `</div>`
  );
}

function reviewScoreClass(verdict: string): string {
  const v = verdict.toLowerCase();
  if (v === "good" || v === "ok" || v === "regression") return v;
  return "unknown";
}

function reviewScoreDimsHtml(score: ReviewScoreView): string {
  const dims = Object.entries(score.dimensions ?? {})
    .filter(([, v]) => Number.isFinite(v))
    .sort(([a], [b]) => (a < b ? -1 : a > b ? 1 : 0));
  if (dims.length === 0) return "";
  return `<div class="reviewscore-dims">${dims.map(([k, v]) => `<span><code>${esc(k)}</code>: <b>${esc(String(v))}</b></span>`).join(" ")}</div>`;
}

/**
 * FIX-343 (AC6) — the retrospective Review Score block: a SINGLE peer-review
 * block. Owner ruling (2026-06-16): the working agent NEVER grades its own work; the
 * cycle's Review Score is produced solely by a fresh-session peer Reviewer
 * (runScorePairing). So there is ONE peer-review badge, never a self/pair
 * binary. The block shows the score N/10, verdict, rationale, the Reviewer
 * (`scoredBy`) AND the Reviewer's fresh `sessionId` — so the independence of the
 * scoring session is VISIBLE (verifiable, not asserted), with the
 * `.roll/peer/*.json`-backed full note linked.
 *
 * A LEGACY self note (`scoring: self` — historical, written before FIX-343) is
 * tolerated on READ and rendered in a clearly muted "legacy self-grade (not
 * gating)" style so its presence is honest, but it is NEVER the live peer block.
 *
 * Dimensions render first/prominent; the project trend stays secondary prose.
 */
function scoreBlockHtml(score: ReviewScoreView | undefined, trend: string | undefined, retro: string | undefined): string {
  if (score === undefined) return retro !== undefined && retro !== "" ? `<p>${esc(retro)}</p>` : "";
  // FIX-343: a `scoring: self` note is a LEGACY artifact (the working agent no
  // longer grades its own work). It is the ONLY non-peer case; everything else is the
  // live peer Review Score.
  const isLegacySelf = score.scoring === "self";
  const href =
    score.href !== undefined && score.href !== "" ? `<a href="${esc(score.href)}">${bi("Full note", "全文 note")}</a>` : "";
  const trendLine = trend !== undefined && trend !== "" ? `<p class="reviewscore-trend">${esc(trend)}</p>` : "";
  if (isLegacySelf) {
    // Legacy self note — muted, explicitly NOT gating. Kept visible for history.
    const reason =
      score.fallbackReason !== undefined && score.fallbackReason !== ""
        ? `<p class="score-legacy-reason">${bi(`Recorded reason: ${score.fallbackReason}`, `留痕原因：${score.fallbackReason}`)}</p>`
        : "";
    return (
      `<div class="reviewscore-card score-card legacy-selfnote reviewscore-${reviewScoreClass(score.verdict)}" data-scoring="self">` +
      `<p class="score-provenance"><span class="score-kind-badge score-kind-legacy">${bi("LEGACY", "历史")}</span> ` +
      `${bi("Legacy self-grade (not gating)", "历史自评（不计入门禁）")}</p>` +
      reason +
      `<p><span class="reviewscore-badge">${esc(score.verdict)}</span> <b>${esc(String(score.score))}</b>/10 · ${esc(score.verdict)} · <code>${esc(score.skill)}</code>${href !== "" ? ` · ${href}` : ""}</p>` +
      (score.note !== "" ? `<p class="note">${esc(score.note)}</p>` : "") +
      reviewScoreDimsHtml(score) +
      trendLine +
      `</div>`
    );
  }
  // The live PEER Review Score block. The line of record: who graded this
  // delivery AND the Reviewer's fresh session id (independence is visible). EN
  // and 中 on separate lines per the bilingual rule.
  const reviewer = score.scoredBy ?? "(reviewer)";
  const provenance = bi(
    `Review Score — by peer Reviewer ${reviewer}`,
    `评审分 —— 由评审 ${score.scoredBy ?? "（评审）"} 评判`,
  );
  // FIX-343 (AC9): surface the Reviewer's fresh session id so "an independent
  // fresh session scored this" is verifiable on the page, not just asserted.
  const sessionLine =
    score.sessionId !== undefined && score.sessionId !== ""
      ? `<p class="score-session">${bi(`Reviewer session: ${score.sessionId}`, `评审 session：${score.sessionId}`)}</p>`
      : "";
  // Dimensions first/prominent (score/verdict/理由 齐备); trend secondary.
  return (
    `<div class="reviewscore-card score-card peerscore reviewscore-${reviewScoreClass(score.verdict)}" data-scoring="peer">` +
    `<p class="score-provenance"><span class="score-kind-badge score-kind-peerscore">${bi("PEER REVIEW", "同行评审")}</span> ${provenance}</p>` +
    sessionLine +
    `<p><span class="reviewscore-badge">${esc(score.verdict)}</span> <b>${esc(String(score.score))}</b>/10 · ${esc(score.verdict)} · <code>${esc(score.skill)}</code>${href !== "" ? ` · ${href}` : ""}</p>` +
    (score.note !== "" ? `<p class="note">${esc(score.note)}</p>` : "") +
    reviewScoreDimsHtml(score) +
    trendLine +
    `</div>`
  );
}

// US-DOSSIER-023 — the three rungs' visual identity, taken verbatim from the
// design reference's truth model: attested = truth-green #178a52, merged =
// attest-pending teal #0d9488, claimed = claim amber #c77d12. "none" reuses the
// muted line so an unreached delivery node never borrows a truth color.
const LADDER_COLOR: Record<DeliveryLadder | "none", string> = {
  attested: "#178a52",
  merged: "#0d9488",
  claimed: "#c77d12",
  none: "#9aa3b2",
};

/**
 * US-DOSSIER-023 — the state-aware delivery banner. Replaces the hardcoded
 * "Merged to main — attested" with one of the three rungs' honest copy
 * (bilingual, EN and 中 on separate lines via `bi`):
 *   - attested → "Merged & attested"            (truth-green `.attest-banner`)
 *   - merged   → "Merged (not yet attested)"    (teal `.merge-banner`)
 *   - claimed  → "Claimed — backlog says Done, no merge evidence yet"
 *                (amber `.claim-banner`)
 * Only the `attested` rung keeps the `.attest-banner` class — the dossier.test
 * stance (attest presence ≠ delivered: a claimed card must NOT carry the
 * truth-green banner) stays true because claimed/merged use their own classes.
 */
function deliveryBanner(ladder: DeliveryLadder | "none", reportHref: string | undefined): string {
  if (ladder === "none") return "";
  const link =
    reportHref !== undefined ? ` · <a href="${esc(reportHref)}">${bi("Acceptance Review Page", "验收 Review Page")}</a>` : "";
  if (ladder === "attested") {
    return (
      `<div class="attest-banner"><span class="mark">✓</span><div>` +
      `${bi("Merged & attested", "已合主干 · 已验收")}${link}</div></div>`
    );
  }
  if (ladder === "merged") {
    return (
      `<div class="attest-banner merge-banner"><span class="mark">◐</span><div>` +
      `${bi("Merged (not yet attested)", "已合主干 — 尚未验收")}${link}</div></div>`
    );
  }
  return (
    `<div class="attest-banner claim-banner"><span class="mark">?</span><div>` +
    `${bi("Claimed — backlog says Done, no merge evidence yet", "仅声明 — 待办标记 Done，尚无合并证据")}</div></div>`
  );
}

/**
 * US-DOSSIER-023 — the claim ↔ truth reconciliation panel (the design
 * reference's two-column 声明/claim vs 真相/truth card). The `recColor`
 * (per-rung border + mark) makes the gap between "what the backlog claims" and
 * "what main proves" legible at a glance:
 *   - claimed  → claim side lit, truth side honest "no merge evidence yet".
 *   - merged   → both sides agree merge happened; truth notes attest pending.
 *   - attested → both sides green, fully reconciled.
 * Hidden for `none` (not even claimed Done — there is nothing to reconcile).
 */
function reconciliationPanel(d: StoryDossierInput, ladder: DeliveryLadder | "none"): string {
  if (ladder === "none") return "";
  const color = LADDER_COLOR[ladder];
  const mark = ladder === "attested" ? "✓" : ladder === "merged" ? "◐" : "?";
  const title =
    ladder === "attested"
      ? bi("Merged & attested", "已合主干 · 已验收")
      : ladder === "merged"
        ? bi("Merged — attestation pending", "已合主干 — 验收待补")
        : bi("Claim recorded — merge evidence unavailable", "已记录声明 — 缺合并证据");
  // 声明/claim side: what the backlog asserts. 真相/truth side: what main proves.
  const claimColor = ladder === "claimed" ? "#c77d12" : "#178a52";
  const claimTxt = bi("backlog ✅ Done", "待办 ✅ Done");
  const truthColor = color;
  const truthTxt =
    ladder === "attested"
      ? bi("merge evidence + full attest", "主干合并证据 + 完整验收")
      : ladder === "merged"
        ? bi("merge evidence on main", "主干有合并证据")
        : bi("no merge on main yet", "主干尚无合并");
  return (
    `<section class="reconcile" data-rung="${ladder}" style="border-color:${color}55;border-left-color:${color}">` +
    `<div class="reconcile-head"><span class="reconcile-mark" style="background:${color}1a;color:${color}">${mark}</span>` +
    `<span class="reconcile-title" style="color:${color}">${title}</span></div>` +
    `<div class="reconcile-cols">` +
    `<div class="reconcile-col reconcile-claim"><div class="reconcile-side">${bi("Claim", "声明")}</div>` +
    `<div class="reconcile-val" style="color:${claimColor}">${claimTxt}</div></div>` +
    `<div class="reconcile-col reconcile-truth"><div class="reconcile-side">${bi("Truth", "真相")}</div>` +
    `<div class="reconcile-val" style="color:${truthColor}">${truthTxt}</div></div>` +
    `</div></section>`
  );
}

// US-DOSSIER-007: emit the shared phase-section anchor (data-phase=<key>) so a
// fully-rendered dossier page stays addressable by `markPhaseDone` — the renderer
// (skeleton) and the mount primitive now share one contract.
function section(phaseKey: string, en: string, zh: string, body: string, empty: boolean): string {
  return `${phaseSectionTag(phaseKey, !empty)}<h2>${bi(en, zh)}</h2>${body}</section>`;
}

/**
 * US-DOSSIER-024 — one piece of inline evidence rendered BENEATH its AC: a
 * screenshot is a real-pixel thumbnail (`<img>` linked to full size); a cast/
 * video is a labelled replay link; a text entry is a doc/contract link. A
 * screenshot whose `href` is missing degrades to a labelled link, never an
 * empty `<img>`.
 */
function acEvidenceItemHtml(e: AcEvidence): string {
  const label = esc(e.label ?? e.href ?? e.kind);
  if (e.kind === "text") {
    if (e.textContent !== undefined) {
      return `<details class="ac-text-evidence"><summary>${label}</summary><pre>${esc(e.textContent)}</pre></details>`;
    }
    return `<span class="ac-evidence-empty">${bi("Text evidence unavailable", "文本证据不可用")}${e.href !== undefined ? `: <code>${esc(e.href)}</code>` : ""}</span>`;
  }
  if (e.kind === "screenshot" && e.href !== undefined) {
    return (
      `<a class="ac-shot" href="${esc(e.href)}" title="${label}">` +
      `<img src="${esc(e.href)}" alt="${label}" loading="lazy"><span class="ac-shot-cap">${label}</span></a>`
    );
  }
  const tag = e.kind === "cast" ? "cast" : e.kind === "video" ? "video" : "doc";
  if (e.href !== undefined) {
    return `<a class="ac-evlink ac-ev-${tag}" href="${esc(e.href)}">${label}</a>`;
  }
  return `<span class="ac-evlink ac-ev-${tag}">${label}</span>`;
}

/**
 * US-DOSSIER-024 — render ONE acceptance criterion as its own block (never a
 * wall of text then a wall of screenshots): the AC id + a status badge + the
 * observable/readonly class chip on the head, then the note, then the inline
 * evidence (screenshot thumbs / text links) and the re-runnable verify command
 * directly beneath it. The block's accent color aligns with the three-state
 * spine ladder (US-DOSSIER-023). An OBSERVABLE AC missing real pixel/cast
 * evidence carries an explicit "evidence gap / 证据缺口" chip and renders in the
 * amber gap state — it is NEVER shown as attested.
 */
function acBlockHtml(row: AcRow, screenshotFiles: readonly string[]): string {
  const kind = classifyAc(row);
  const state = acDisplayState(row, kind, screenshotFiles);
  const color = AC_STATE_COLOR[state];
  const [badgeEn, badgeZh] = AC_BADGE[row.status] ?? [esc(row.status), esc(row.status)];
  const gap = state === "gap";
  // The status badge: a demoted observable-gap AC never wears its declared
  // (possibly "✓ pass") badge — it shows the honest gap state instead.
  const statusBadge = gap
    ? `<span class="ac-badge ac-badge-gap">${bi("◇ unproven", "◇ 未证实")}</span>`
    : `<span class="ac-badge" style="color:${color};border-color:${color}66">${bi(badgeEn, badgeZh)}</span>`;
  const kindChip =
    kind === "observable"
      ? `<span class="ac-kind ac-kind-obs">${bi("observable", "可观测")}</span>`
      : `<span class="ac-kind ac-kind-ro">${bi("readonly", "只读")}</span>`;
  const gapChip = gap
    ? `<span class="ac-gap-chip">${bi("evidence gap", "证据缺口")}</span>`
    : "";
  const note = row.note !== undefined && row.note !== "" ? `<p class="ac-note">${esc(row.note)}</p>` : "";
  // Inline evidence beneath the AC. Screenshot entries from ac-map first, then
  // on-disk screenshot files not already named by ac-map (real captured pixels),
  // then text/cast links. Dedup by BASENAME — ac-map hrefs (`screenshots/x.png`,
  // `../screenshots/x.png`) and on-disk hrefs (`latest/screenshots/x.png`) point
  // at the same file under different relative prefixes. An observable gap shows
  // the explicit honest empty state.
  const evRows = row.evidence ?? [];
  const baseName = (h: string): string => h.split("/").pop() ?? h;
  const namedShots = new Set(evRows.filter((e) => e.kind === "screenshot" && e.href !== undefined).map((e) => baseName(e.href as string)));
  const extraShots = screenshotFiles
    .filter((h) => !namedShots.has(baseName(h)))
    .map((h) => acEvidenceItemHtml({ kind: "screenshot", href: h, label: baseName(h) }));
  const evItems = [...evRows.map(acEvidenceItemHtml), ...extraShots];
  const evidenceBlock =
    evItems.length > 0
      ? `<div class="ac-evidence">${evItems.join("")}</div>`
      : gap
        ? `<p class="ac-evidence-empty">${bi(
            "Observable AC — no screenshot/cast captured yet",
            "可观测 AC — 尚无截图/录屏",
          )}</p>`
        : "";
  // The re-runnable verify command (EVID-010), now inline within the AC block.
  const verify =
    row.verify !== undefined && row.verify !== ""
      ? `<div class="ac-verify"><button class="copy-btn" data-copy="${esc(row.verify)}" title="copy 复制" type="button">⧉</button><code>${esc(row.verify)}</code>` +
        (row.tests !== undefined && row.tests.length > 0
          ? `<ul class="ac-tests">${row.tests.map((t) => `<li><code>${esc(t)}</code></li>`).join("")}</ul>`
          : "") +
        `</div>`
      : "";
  return (
    `<div class="ac-block ac-state-${state}" data-ac="${esc(row.ac)}" data-kind="${kind}" style="border-left-color:${color}">` +
    `<div class="ac-head"><code class="ac-id">${esc(row.ac)}</code>${statusBadge}${kindChip}${gapChip}</div>` +
    note +
    evidenceBlock +
    verify +
    `</div>`
  );
}

/** US-DOSSIER-024 — the whole per-AC block list for the delivery station. */
function acBlocksHtml(rows: readonly AcRow[], screenshotFiles: readonly string[]): string {
  if (rows.length === 0) return "";
  return `<div class="ac-blocks">${rows.map((r) => acBlockHtml(r, screenshotFiles)).join("")}</div>`;
}

/** US-OBS-034 — Execution Cast block for the story dossier page. */
function dossierExecutionCastBlock(
  summary: CycleRoleSummary | undefined,
  summaryHref: string | undefined,
  artifactHrefs: Record<string, string> | undefined,
): string {
  if (summary === undefined) return "";
  const projection = buildExecutionCastProjection(summary);

  const stateBadge = (state: CycleRoleAttemptState): string => {
    switch (state) {
      case "accepted": return `<span class="cast-badge cast-ok">✔</span>`;
      case "rejected": return `<span class="cast-badge cast-fail">✗</span>`;
      case "failed": return `<span class="cast-badge cast-fail">✗</span>`;
      case "returned": return `<span class="cast-badge cast-warn">↺</span>`;
      case "selected": return `<span class="cast-badge cast-pending">◷</span>`;
      case "started": return `<span class="cast-badge cast-pending">▶</span>`;
      case "parsed": return `<span class="cast-badge cast-ok">✓</span>`;
      case "not_required": return `<span class="cast-badge cast-muted">—</span>`;
      case "not_available": return `<span class="cast-badge cast-fail">⛔</span>`;
      case "skipped": return `<span class="cast-badge cast-muted">⏭</span>`;
    }
  };

  const roleLabel = (role: CycleRoleName, state: CycleRoleAttemptState): string => {
    if (role === "builder") return bi("Builder", "构建者");
    if (role === "peer_reviewer") return bi("Peer Reviewer", "同行评审");
    if (role === "evaluator") return state === "accepted" ? bi("Evaluator", "评审员") : bi("Evaluator (failed)", "评审失败");
    if (role === "attest_gate") return bi("Attest Gate", "验收门禁");
    if (role === "designer") return bi("Designer", "设计者");
    return role;
  };

  const makeRow = (row: ExecutionCastRow): string => {
    const agentHtml = row.agent !== null ? `<code>${esc(row.agent)}</code>` : `<span class="text-muted">${bi("none", "无")}</span>`;
    const extra: string[] = [];
    if (row.model !== undefined) extra.push(row.model);
    if (row.score !== undefined) extra.push(`${row.score}/10`);
    if (row.verdict !== undefined) extra.push(row.verdict);
    if (row.findings !== undefined) extra.push(`${row.findings} ${bi("findings", "意见")}`);
    if (row.cause !== undefined) extra.push(row.cause);
    const extraHtml = extra.length > 0 ? ` <span class="text-muted">${esc(extra.join(" · "))}</span>` : "";
    return `<div class="dc-row"><span class="dc-role">${roleLabel(row.role, row.state)}</span>` +
      `<span class="dc-agent">${agentHtml}${extraHtml}</span>` +
      `<span class="dc-state">${stateBadge(row.state)}</span></div>`;
  };

  const summaryLinks = summaryHref !== undefined
    ? `<p class="text-muted cast-footnote">📄 <a href="${esc(summaryHref)}">summary.json</a> · <a href="${esc(summaryHref.replace(/\.json$/, ".md"))}">summary.md</a></p>`
    : "";
  const artifactLinks = projection.artifactLinks
    .map((a) => {
      const href = artifactHrefs?.[a.path];
      return href === undefined || href === "" ? "" : `<a href="${esc(href)}">${esc(a.label)}</a>`;
    })
    .filter((x) => x !== "")
    .join(" · ");
  const artifacts = artifactLinks !== "" ? `<p class="text-muted cast-footnote">🔗 ${artifactLinks}</p>` : "";

  return `<details id="execution-cast" class="execution-cast-dossier"><summary>🎭 ${bi("Execution Cast", "执行阵容")} · ${esc(projection.builderAgent ?? "—")}</summary>
<div class="dc-grid">${projection.rows.map(makeRow).join("")}</div>
<p class="text-muted cast-footnote">${bi("Cycle", "周期")} <code>${esc(summary.cycleId)}</code> · ${esc(summary.executionProfile)}</p>
${summaryLinks}
${artifacts}
</details>`;
}

function cycleRoleArtifactHrefsFrom(fromDir: string, summary: CycleRoleSummary): Record<string, string> {
  const out: Record<string, string> = {};
  for (const link of buildExecutionCastProjection(summary).artifactLinks) {
    out[link.path] = relativePath(fromDir, link.path);
  }
  return out;
}

/**
 * US-BROW-009b — browser operations summary block for the Execution station.
 * Renders managed/interactive/capture readiness from the truth adapter.
 * Returns empty string when no truth is available (no browser ops recorded).
 */
function browserDossierBlock(truth?: BrowserOperationsTruth): string {
  if (truth === undefined) return "";

  const badge = (status: string): string => {
    const color = status === "ready" ? "var(--pass)" : status === "degraded" || status === "expired" ? "var(--warn)" : "var(--muted)";
    return `<span style="color:${color};font-weight:600;">${status}</span>`;
  };

  const row = (label: string, status: string, reason?: string, expiresAt?: string): string => {
    let detail = reason ?? "";
    if (expiresAt) detail = detail ? `${detail} (expires ${esc(expiresAt)})` : `expires ${esc(expiresAt)}`;
    return `<div class="dc-row"><span class="dc-role">${esc(label)}</span><span class="dc-agent">${badge(status)}${detail ? ` — ${esc(detail)}` : ""}</span><span class="dc-state"></span></div>`;
  };

  return (
    `<details class="execution-cast-dossier" open>` +
    `<summary>${bi("Browser operations", "浏览器操作")}</summary>` +
    `<div class="dc-grid">` +
    row("managed", truth.managed.status, truth.managed.unavailableReason) +
    row("interactive", truth.lease.status, truth.lease.unavailableReason, truth.lease.expiresAt) +
    row("capture", truth.capture.status, truth.capture.unavailableReason) +
    `</div></details>`
  );
}

/** Render the dossier page. */
export function renderStoryDossier(d: StoryDossierInput): string {
  const s = d.story;
  // US-DOSSIER-003: definition station = story primitive (As a / I want / So
  // that). Falls back to the wish blockquote, then an honest empty state.
  const n = d.narrative;
  const hasNarr = n !== undefined && (n.asA !== undefined || n.iWant !== undefined || n.soThat !== undefined);
  const narrRow = (label: [string, string], v: string | undefined): string =>
    v === undefined || v === "" ? "" : `<div class="np-row"><dt>${bi(label[0], label[1])}</dt><dd>${esc(v)}</dd></div>`;
  const definition = hasNarr
    ? `<dl class="story-primitive">` +
      narrRow(["As a", "作为"], n?.asA) +
      narrRow(["I want", "我要"], n?.iWant) +
      narrRow(["So that", "以便"], n?.soThat) +
      `</dl>`
    : d.wish !== undefined && d.wish !== ""
      ? `<div class="wish-quote">${esc(d.wish)}</div>`
      : `<p class="empty">${bi("No story primitive in spec.md", "spec.md 未记录故事原语")}</p>`;
  const defEmpty = !hasNarr && (d.wish === undefined || d.wish === "");
  // US-DOSSIER-003: AC checklist (the definition of done) rendered inline.
  const acChecklist =
    (d.acItems?.length ?? 0) > 0
      ? `<ul class="ac-checklist">${(d.acItems ?? [])
          .map((a) => `<li>${a.checked ? "☑" : "☐"} ${esc(a.text)}</li>`)
          .join("")}</ul>`
      : `<p class="empty">${bi("No AC in spec.md", "spec.md 未记录 AC")}</p>`;
  const peerReview = peerReviewHtml(d.peerReview);
  const designBits: string[] = [];
  if ((d.design?.length ?? 0) > 0) designBits.push(`<ul>${(d.design ?? []).map((b) => `<li>${esc(b)}</li>`).join("")}</ul>`);
  if (peerReview !== "") designBits.push(peerReview);
  const design = designBits.length > 0 ? designBits.join("\n") : `<p class="empty">${bi("Not yet designed", "尚未设计")}</p>`;

  // US-BROW-009b: browser operations summary from truth adapter.
  const browserDossierHtml = browserDossierBlock(d.browserTruth);
  // US-BROW-013: optional timeline — empty when no browser facts exist.
  const browserTimelineHtml = renderBrowserOperationsTimelineHtml(d.browserTimeline, {
    viewerAuthorized: true,
    artifactHrefs: d.browserTimelineArtifactHrefs,
  });
  const browserHtml = browserDossierHtml + browserTimelineHtml;

  const execution =
    (d.commits?.length ?? 0) > 0
      ? `<p>${bi(`${(d.commits ?? []).length} TCR commits`, `${(d.commits ?? []).length} 个 TCR 提交`)}</p>` +
        `<ul class="muted">${(d.commits ?? []).map((c) => `<li><code>${esc(c)}</code></li>`).join("")}</ul>` +
        executionRefsHtml(d.executionRefs ?? []) +
        browserHtml
      : (d.executionRefs?.length ?? 0) > 0
        ? executionRefsHtml(d.executionRefs ?? []) + browserHtml
        : browserHtml !== ""
          ? browserHtml
          : `<p class="empty">${bi("No cycles yet", "暂无周期")}</p>`;
  // US-DOSSIER-023: the delivery node's ladder rung drives both the spine and the
  // banner, so the page never contradicts itself (claimed→merged→attested).
  const ladder = storyDeliveryState(d);
  const banner = deliveryBanner(ladder, d.reportHref);
  // US-DOSSIER-024: each AC is its own block (AC text + ladder-aligned status
  // badge + observable/readonly chip + inline evidence beneath it), replacing
  // the old "wall of text then wall of screenshots" table. Observable ACs with
  // no real screenshot/cast carry an explicit evidence-gap chip and never attest.
  const acBlocks = acBlocksHtml(d.acRows ?? [], d.screenshotFiles ?? []);
  const hasDeliveryBody =
    ladder !== "none" ||
    s.delivered ||
    (d.acRows?.length ?? 0) > 0 ||
    hasDeliveryEvidence(d.deliveryEvidence) ||
    hasDynamicEvidence(d.dynamicEvidence);
  const delivery = hasDeliveryBody
    ? banner + dossierExecutionCastBlock(d.cycleRoleSummary, d.cycleRoleSummaryHref, d.cycleRoleArtifactHrefs) + deliveryEvidenceHtml(d.deliveryEvidence) + dynamicEvidenceHtml(d.dynamicEvidence) + acBlocks
    : `<p class="empty">${bi("Not yet delivered", "尚未交付")}</p>`;
  const corrections = correctionTraceHtml(d.correctionActions);
  const retroContent = scoreBlockHtml(d.reviewScore, d.reviewScoreTrend, d.retro);
  const retro = retroContent !== "" ? retroContent : `<p class="empty">${bi("Not yet written", "尚未撰写")}</p>`;

  return (
    `<!DOCTYPE html>\n<html lang="zh-CN">\n<head>\n<meta charset="UTF-8">\n` +
    `<meta name="viewport" content="width=device-width, initial-scale=1">\n` +
    `<title>${esc(s.id)}${s.title !== undefined ? ` — ${esc(s.title)}` : ""}</title>\n` +
    `<style>\n${CHROME_CSS}${DOSSIER_CSS}` +
    `.execution-cast-dossier { margin:12px 0; border:1px solid var(--line); border-radius:8px; padding:8px 14px; background:var(--bg-raise); }\n` +
    `.execution-cast-dossier summary { cursor:pointer; font-weight:600; font-size:14px; }\n` +
    `.dc-grid { display:grid; grid-template-columns:auto 1fr auto; gap:4px 10px; margin:8px 0 0; }\n` +
    `.dc-row { display:contents; }\n` +
    `.dc-row > * { padding:2px 0; font-size:13px; }\n` +
    `.dc-role { color:var(--muted); font-weight:600; font-size:12.5px; white-space:nowrap; }\n` +
    `.dc-agent { font-size:13px; }\n` +
    `.dc-state { text-align:right; }\n` +
    `.cast-badge { display:inline-block; width:18px; text-align:center; }\n` +
    `.cast-ok { color:var(--pass); } .cast-fail { color:var(--fail); } .cast-warn { color:var(--warn); }\n` +
    `.cast-pending { color:var(--info); } .cast-muted { color:var(--muted); }\n` +
    `.cast-footnote { font-size:12px; margin:6px 0 0; }\n` +

    `.phase-done { border-left:4px solid var(--pass); } .phase-pending { border-left:4px solid var(--line); }\n` +
    // US-DOSSIER-023: the three delivery rungs on the lifecycle spine — claimed
    // (hatched/hollow, a wish not yet truth) → merged (solid attest-pending teal,
    // honest middle) → attested (solid truth-green). Distinct so the spine never
    // paints "just claimed" as merged or "merged not attested" as full green.
    `.spine .node.claimed .dot { border-color:#c77d12; background:repeating-linear-gradient(45deg,#c77d12 0 2px,transparent 2px 5px); }\n` +
    `.spine .node.claimed .tag { color:#c77d12; }\n` +
    `.spine .node.merged .dot { border-color:#0d9488; background:#0d9488; }\n` +
    `.spine .node.merged .tag { color:var(--fg); }\n` +
    `.spine .node.attested .dot { border-color:#178a52; background:#178a52; }\n` +
    `.spine .node.attested .tag { color:var(--fg); }\n` +
    // US-DOSSIER-023: the alternate-state delivery banners (merged = teal,
    // claimed = amber); the truth-green `.attest-banner` is attested-only.
    `.attest-banner.merge-banner { border-color:#0d948855; } .attest-banner.merge-banner .mark { color:#0d9488; }\n` +
    `.attest-banner.claim-banner { border-color:#c77d1255; border-style:dashed; } .attest-banner.claim-banner .mark { color:#c77d12; }\n` +
    // US-DOSSIER-023: the claim ↔ truth reconciliation panel (two columns, the
    // design reference's 声明/claim vs 真相/truth card; recColor border per rung).
    `.reconcile { border:1px solid var(--line); border-left-width:4px; border-radius:12px; background:var(--bg-raise); overflow:hidden; margin:18px 0; }\n` +
    `.reconcile-head { display:flex; align-items:center; gap:11px; padding:13px 16px; border-bottom:1px solid var(--line); }\n` +
    `.reconcile-mark { display:inline-flex; align-items:center; justify-content:center; width:22px; height:22px; border-radius:50%; font-weight:700; font-size:13px; flex:none; }\n` +
    `.reconcile-title { font-size:15px; font-weight:600; }\n` +
    `.reconcile-cols { display:grid; grid-template-columns:1fr 1fr; }\n` +
    `.reconcile-col { padding:13px 16px; } .reconcile-claim { border-right:1px solid var(--line); }\n` +
    `.reconcile-side { font:600 10px/1 var(--mono); letter-spacing:.1em; text-transform:uppercase; color:var(--muted); }\n` +
    `.reconcile-val { margin-top:7px; font:13px/1.4 var(--mono); }\n` +
    `@media (max-width:680px) { .reconcile-cols { grid-template-columns:1fr; } .reconcile-claim { border-right:none; border-bottom:1px solid var(--line); } }\n` +
    `.story-primitive { margin:0; } .story-primitive .np-row { display:flex; gap:10px; margin:4px 0; }\n` +
    `.story-primitive dt { flex:0 0 64px; color:var(--muted); font:600 12.5px/1.7 var(--sans); }\n` +
    `.story-primitive dd { margin:0; flex:1; }\n` +
    `.ac-checklist { list-style:none; padding:0; margin:0; } .ac-checklist li { margin:3px 0; }\n` +
    `.verify-cell code { font-size:12px; } .verify-cell .copy-btn { margin-right:6px; cursor:pointer; border:1px solid var(--line); background:var(--bg-raise); color:var(--muted); border-radius:4px; padding:0 5px; font-size:12px; }\n` +
    `.verify-cell .copy-btn.copied { color:var(--pass); border-color:var(--pass); }\n` +
    `.ac-tests { list-style:none; padding:0; margin:4px 0 0; } .ac-tests li { font-size:11.5px; color:var(--muted); margin:1px 0; }\n` +
    `.verify-empty { color:var(--muted); font-size:12px; }\n` +
    // US-DOSSIER-024: per-AC evidence blocks — each AC is its own card (AC id +
    // ladder-aligned status badge + observable/readonly chip), then note, then
    // the inline evidence (screenshot thumbnails / text links) beneath it, then
    // the re-runnable verify command. The left border + gap chip color follow
    // the three-state spine ladder so an unproven observable AC reads honestly.
    `.ac-blocks { display:grid; gap:12px; margin:6px 0 0; }\n` +
    `.ac-block { border:1px solid var(--line); border-left:4px solid var(--line); border-radius:10px; padding:11px 14px; background:var(--bg-raise); }\n` +
    `.ac-head { display:flex; align-items:center; flex-wrap:wrap; gap:9px; }\n` +
    `.ac-head .ac-id { font:600 12.5px/1.4 var(--mono); }\n` +
    `.ac-badge { display:inline-flex; align-items:center; border:1px solid var(--line); border-radius:999px; padding:1px 9px; font:600 11.5px/1.5 var(--sans); }\n` +
    `.ac-badge-gap { color:#c77d12; border-color:#c77d1266; }\n` +
    `.ac-kind { font:600 9.5px/1 var(--mono); letter-spacing:.08em; text-transform:uppercase; border-radius:4px; padding:3px 6px; border:1px solid var(--line); }\n` +
    `.ac-kind-obs { color:#2d54e8; border-color:#2d54e855; } .ac-kind-ro { color:var(--muted); }\n` +
    `.ac-gap-chip { font:600 9.5px/1 var(--mono); letter-spacing:.06em; text-transform:uppercase; color:#c77d12; border:1px solid #c77d1266; background:#c77d121a; border-radius:4px; padding:3px 7px; }\n` +
    `.ac-note { margin:8px 0 0; font-size:13px; line-height:1.5; }\n` +
    `.ac-evidence { display:flex; flex-wrap:wrap; gap:10px; margin:9px 0 0; align-items:flex-start; }\n` +
    `.ac-shot { display:flex; flex-direction:column; gap:4px; width:160px; text-decoration:none; }\n` +
    `.ac-shot img { width:160px; height:96px; object-fit:cover; border:1px solid var(--line); border-radius:6px; background:#fff; display:block; }\n` +
    `.ac-shot-cap { font:10.5px/1.3 var(--mono); color:var(--muted); word-break:break-word; }\n` +
    `.ac-text-evidence { flex:1 1 280px; min-width:min(100%,280px); border:1px solid var(--line); border-radius:6px; padding:7px 9px; background:color-mix(in srgb, var(--fg) 3%, transparent); }\n` +
    `.ac-text-evidence summary { cursor:pointer; font:600 11.5px/1.5 var(--mono); color:var(--muted); }\n` +
    `.ac-text-evidence pre { margin:7px 0 0; max-height:220px; overflow:auto; white-space:pre-wrap; word-break:break-word; font-size:11.5px; line-height:1.5; }\n` +
    `.ac-evlink { display:inline-flex; align-items:center; gap:5px; font:11.5px/1.5 var(--mono); border:1px solid var(--line); border-radius:6px; padding:5px 9px; color:var(--muted); text-decoration:none; }\n` +
    `.ac-evlink.ac-ev-cast, .ac-evlink.ac-ev-video { color:#2d54e8; border-color:#2d54e855; }\n` +
    `.ac-evidence-empty { margin:9px 0 0; font-size:12px; color:#c77d12; }\n` +
    `.ac-verify { margin:9px 0 0; } .ac-verify code { font-size:12px; }\n` +
    `.ac-verify .copy-btn { margin-right:6px; cursor:pointer; border:1px solid var(--line); background:var(--bg-raise); color:var(--muted); border-radius:4px; padding:0 5px; font-size:12px; }\n` +
    `.ac-verify .copy-btn.copied { color:var(--pass); border-color:var(--pass); }\n` +
    `@media (max-width:680px) { .ac-shot, .ac-shot img { width:100%; } }\n` +
    `.delivery-evidence h3 { font:600 14px/1.4 var(--serif); margin:12px 0 6px; }\n` +
    `.delivery-evidence dl { display:grid; grid-template-columns:120px 1fr; gap:6px 12px; margin:0; }\n` +
    `.delivery-evidence dt { color:var(--muted); font:600 12px/1.7 var(--sans); }\n` +
    `.delivery-evidence dd { margin:0; }\n` +
    `.delivery-files { list-style:none; padding:0; margin:0; } .delivery-files li { margin:2px 0; }\n` +
    `.delivery-timeline { margin:0; padding-left:18px; } .delivery-timeline li { margin:2px 0; }\n` +
    `.browser-ops-timeline { margin:12px 0; border:1px solid var(--line); border-radius:8px; padding:8px 14px; background:var(--bg-raise); }\n` +
    `.browser-ops-timeline summary { cursor:pointer; font-weight:600; font-size:14px; }\n` +
    `.bot-timeline, .bot-absences { list-style:none; margin:8px 0 0; padding:0; font-size:13px; }\n` +
    `.bot-row { padding:3px 0 3px 10px; border-left:2px solid var(--line); }\n` +
    `.bot-row.bot-present { border-left-color:var(--info); }\n` +
    `.bot-row.bot-absent, .bot-row.bot-unknown { color:var(--muted); }\n` +
    `.bot-absences-label { margin:10px 0 0; font:600 12px/1.4 var(--sans); color:var(--muted); }\n` +
    `.bot-artifact-locked { color:var(--muted); }\n` +
    `.dynamic-evidence h3 { font:600 14px/1.4 var(--serif); margin:12px 0 6px; }\n` +
    `.dynamic-evidence ul { list-style:none; padding:0; margin:0; display:grid; gap:8px; }\n` +
    `.dynamic-evidence video { width:100%; max-width:680px; border:1px solid var(--line); border-radius:6px; background:#000; }\n` +
    `.dynamic-evidence p { margin:3px 0 0; }\n` +
    `.story-graph dl { display:grid; grid-template-columns:120px 1fr; gap:8px 12px; margin:0; }\n` +
    `.story-graph dt { color:var(--muted); font:600 12px/1.7 var(--sans); }\n` +
    `.story-graph dd { margin:0; }\n` +
    `.graph-links { list-style:none; display:flex; flex-wrap:wrap; gap:6px; padding:0; margin:0; }\n` +
    `.graph-links li { margin:0; }\n` +
    `.correction-trace { list-style:none; padding:0; margin:0; } .correction-trace li { border:1px solid var(--line); border-radius:8px; padding:9px 11px; margin:8px 0; background:var(--bg-raise); }\n` +
    `.correction-trace p { margin:0 0 3px; } .correction-trace p:last-child { margin-bottom:0; }\n` +
    `.peer-review { border:1px solid var(--line); border-radius:8px; padding:10px 12px; margin-top:10px; background:var(--bg-raise); }\n` +
    `.peer-review h3 { font:600 14px/1.4 var(--serif); margin:0 0 6px; }\n` +
    `.peer-review p { margin:0 0 6px; } .peer-review ol { margin:6px 0 0; padding-left:22px; }\n` +
    `.peer-review li { margin:7px 0; } .peer-review ul { margin:4px 0 0; padding-left:18px; color:var(--muted); }\n` +
    `.peer-verdict { display:inline-block; border:1px solid var(--line); border-radius:999px; padding:1px 8px; font-size:12px; font-weight:600; }\n` +
    `.peer-agree { color:var(--pass); } .peer-refine { color:var(--warn); } .peer-object, .peer-escalate { color:var(--fail); }\n` +
    `.reviewscore-card { border:1px solid var(--line); border-radius:8px; padding:10px 12px; background:var(--bg-raise); }\n` +
    `.reviewscore-card p { margin:0 0 6px; } .reviewscore-card p:last-child { margin-bottom:0; }\n` +
    `.reviewscore-badge { display:inline-block; border:1px solid var(--line); border-radius:999px; padding:1px 8px; font-size:12px; font-weight:600; }\n` +
    `.reviewscore-good .reviewscore-badge { color:var(--pass); } .reviewscore-ok .reviewscore-badge { color:var(--warn); } .reviewscore-regression .reviewscore-badge { color:var(--fail); }\n` +
    `.reviewscore-dims, .reviewscore-trend { color:var(--muted); font-size:12.5px; margin-top:4px; }\n` +
    // FIX-343 (AC6): single peer Review Score block. The live peer score leads
    // with a truth-green PEER REVIEW badge + prominent left accent and shows the
    // Reviewer's session id. A legacy self note (historical, not gating) renders
    // muted/dashed — never a live pair/self binary.
    `.score-provenance { font:600 13px/1.5 var(--sans); display:flex; align-items:center; gap:8px; flex-wrap:wrap; }\n` +
    `.score-kind-badge { display:inline-block; border-radius:4px; padding:2px 7px; font:700 10px/1 var(--mono); letter-spacing:.08em; }\n` +
    `.score-card.peerscore { border-left:4px solid #178a52; } .score-kind-peerscore { color:#178a52; border:1px solid #178a5255; background:#178a521a; }\n` +
    `.score-card.legacy-selfnote { border-left:4px solid var(--muted); border-left-style:dashed; opacity:.75; } .score-kind-legacy { color:var(--muted); border:1px solid var(--line); background:transparent; }\n` +
    `.score-session { color:var(--muted); font-size:12px; font-family:var(--mono); word-break:break-all; }\n` +
    `.score-legacy-reason { color:var(--muted); font-size:12.5px; }\n` +
    `@media (max-width:680px) { .delivery-evidence dl, .story-graph dl { grid-template-columns:1fr; } }\n` +
    `</style>\n${CHROME_SCRIPT}\n</head>\n<body>\n${CHROME_CONTROLS}\n` +
    `<div class="masthead">\n` +
    `<p class="crumb"><a href="../../index.html#backlog">${bi("Backlog", "待办")}</a> / <a href="../index.html">${esc(s.epic)}</a> / ${esc(s.id)}</p>\n` +
    `<p class="kicker">Roll · ${bi("Story Dossier", "故事档案")}</p>\n` +
    `<h1><code>${esc(s.id)}</code></h1>\n` +
    // US-DOSSIER-018: the dossier head teaches the CLI — an unfinished story
    // carries its real pickup command as a copyable chip (✓ copied feedback).
    (s.delivered
      ? ""
      : `<p><code class="copy-chip" data-copy="roll loop go --cards ${esc(s.id)}" style="cursor:pointer;border:1px dashed currentColor;border-radius:6px;padding:2px 8px;font-size:12px;">roll loop go --cards ${esc(s.id)}</code></p>\n` +
        `<script>document.addEventListener("DOMContentLoaded",function(){var c=document.querySelector(".copy-chip");if(!c)return;c.addEventListener("click",function(){var t=this.getAttribute("data-copy");var s=this;try{navigator.clipboard.writeText(t).then(function(){var o=s.textContent;s.textContent="✓ copied";setTimeout(function(){s.textContent=o;},1200);});}catch(e){}});});</script>\n`) +
    (s.title !== undefined ? `<p class="lede">${esc(s.title)}</p>\n` : "") +
    `<div class="kv"><span class="type type-${esc(s.type)}">${esc(s.type)}</span>` +
    `<span>${bi("epic", "史诗")} <b>${esc(s.epic)}</b></span>` +
    (d.context !== undefined && d.context !== "" ? `<span>${bi("context", "上下文")} <b>${esc(d.context)}</b></span>` : "") +
    (s.created !== undefined ? `<span>${bi("created", "创建")} <b>${esc(s.created)}</b></span>` : "") +
    `<span><a href="spec.html">${bi("Design doc", "设计文档")}</a></span>` +
    `</div>\n</div>\n` +
    (s.legacy
      ? `<div class="legacy-banner">${bi(
          "Legacy delivery — completed before v3; honored as done, but without the v3 evidence trail (attest report / AC map / Review Score). Not re-instrumented.",
          "历史交付 —— v3 之前已完成；按完成对待，但没有 v3 的证据链（验收报告 / AC 映射 / 自评），也不会回头补做。",
        )}</div>\n`
      : "") +
    storySpine(d) +
    // US-DOSSIER-023: legacy cards carry no v3 truth chain → nothing to
    // reconcile; the muted spine + legacy banner already tell the honest story.
    (s.legacy ? "" : reconciliationPanel(d, ladder)) +
    storyGraphHtml(d.storyGraph) +
    section("definition", "Definition", "立项", definition, defEmpty) +
    section("acceptance", "Acceptance Criteria", "验收标准", acChecklist, (d.acItems?.length ?? 0) === 0) +
    section("design", "Design", "设计", design, (d.design?.length ?? 0) === 0 && d.peerReview === undefined) +
    section("execution", "Execution", "执行", execution, (d.commits?.length ?? 0) === 0 && (d.executionRefs?.length ?? 0) === 0) +
    section("delivery", "Delivery", "交付", delivery, !hasDeliveryBody) +
    (corrections !== "" ? section("corrections", "Correction trace", "纠正留痕", corrections, false) : "") +
    section("retrospective", "Retrospective", "复盘", retro, d.reviewScore === undefined && (d.retro === undefined || d.retro === "")) +
    // FIX-286: footer keeps a SINGLE spec link (the readable rendered spec.html);
    // the redundant `spec.md (raw)` link was dropped (owner: 两个链接指向几乎同一份东西,留一个).
    `<footer>Roll · <a href="spec.html">spec</a></footer>\n` +
    // EVID-010: inline copy handler (display only — never executes the command).
    `<script>document.addEventListener("click",function(e){var b=e.target.closest&&e.target.closest(".copy-btn");if(!b||!navigator.clipboard)return;var t=b.getAttribute("data-copy")||"";navigator.clipboard.writeText(t).then(function(){b.classList.add("copied");setTimeout(function(){b.classList.remove("copied")},1200);}).catch(function(){});});</script>\n` +
    `</body>\n</html>\n`
  );
}

// ── US-DOSSIER-001d — fill the dossier input from the real card folder ──────

/**
 * Read everything renderStoryDossier needs from the card folder + repo:
 * spec.md (wish = first blockquote; design = bullets under a 方案/Solution/
 * Design heading), ac-map.json, the latest/ report, the newest Review Score
 * note, and the story's `tcr:` commits from git history. Every read is
 * best-effort — a missing source renders as an honest empty state.
 */
/**
 * FIX-334 — pull the `**Bold**:` primitive line off a FIX-format spec body.
 * Matches `**<label>**: <text>` (EN or 中 label, optional colon) and returns the
 * text after the colon. Returns "" when absent. General over any FIX spec.
 */
function fixPrimitiveLine(spec: string, labels: readonly string[]): string {
  for (const label of labels) {
    const re = new RegExp(`^\\*\\*${label}\\*\\*\\s*[:：]?\\s*(.*)$`, "im");
    const m = re.exec(spec);
    if (m !== null) {
      const text = (m[1] ?? "").trim();
      if (text !== "") return text;
    }
  }
  return "";
}

/**
 * FIX-334 — derive the Definition-station wish for a FIX-format spec that has no
 * As-a/I-want narrative and no blockquote. Order: `**Problem**` (what's broken)
 * → `**Solution**` (the intent) → the spec's H1 title line. Returns "" only when
 * the spec is truly bare. General: works for ANY FIX card, not one fixture.
 */
export function parseFixWish(spec: string): string {
  const problem = fixPrimitiveLine(spec, ["Problem", "问题"]);
  if (problem !== "") return problem;
  const solution = fixPrimitiveLine(spec, ["Solution", "方案", "解决", "Fix"]);
  if (solution !== "") return solution;
  const h1 = /^#\s+(.*)$/m.exec(spec);
  return h1 !== null ? (h1[1] ?? "").trim() : "";
}

/**
 * FIX-334 — derive Design-station bullets for a FIX-format spec whose approach
 * lives in `**Root Cause**:` / `**Solution**:` bold lines rather than a
 * `## Solution` heading + bullets. Each present primitive becomes one labelled
 * bullet. General over any FIX spec; empty when none are present.
 */
export function parseFixDesign(spec: string): string[] {
  const bullets: string[] = [];
  const rootCause = fixPrimitiveLine(spec, ["Root Cause", "根因", "原因"]);
  if (rootCause !== "") bullets.push(`${bi("Root cause", "根因")}: ${rootCause}`);
  const solution = fixPrimitiveLine(spec, ["Solution", "方案", "解决", "Fix"]);
  if (solution !== "") bullets.push(`${bi("Solution", "方案")}: ${solution}`);
  return bullets;
}

export function collectStoryDossierInput(projectPath: string, story: DossierStory, cache?: DossierRunCache): StoryDossierInput {
  const gitFacts = cache === undefined ? undefined : cache.git;
  const dir = joinPath(projectPath, ".roll", "features", story.epic, story.id);
  const out: StoryDossierInput = { story };
  let searchableCardText = "";

  // spec.md → wish + design bullets.
  try {
    const spec = readFile(joinPath(dir, "spec.md"));
    searchableCardText += `\n${spec}`;
    const quote: string[] = [];
    for (const l of spec.split("\n")) {
      const m = /^>\s?(.*)$/.exec(l);
      if (m !== null) quote.push((m[1] ?? "").trim());
      else if (quote.length > 0) break;
    }
    const wish = quote.join(" ").replace(/\s+/g, " ").trim();
    if (wish !== "") out.wish = wish;
    // US-DOSSIER-003: story primitive (As a / I want / So that).
    const narr: { asA?: string; iWant?: string; soThat?: string } = {};
    const asA = /^[-*]\s*As a\s+(.*)$/im.exec(spec);
    const iWant = /^[-*]\s*I want\s+(.*)$/im.exec(spec);
    const soThat = /^[-*]\s*So that\s+(.*)$/im.exec(spec);
    if (asA !== null) narr.asA = (asA[1] ?? "").trim();
    if (iWant !== null) narr.iWant = (iWant[1] ?? "").trim();
    if (soThat !== null) narr.soThat = (soThat[1] ?? "").trim();
    if (narr.asA !== undefined || narr.iWant !== undefined || narr.soThat !== undefined) out.narrative = narr;
    // FIX-334: a FIX-format spec carries no As-a/I-want narrative — its wish lives
    // in the `**Problem**:` line. When neither the blockquote nor the narrative
    // primitive fills the Definition station, fall back to the FIX primitives
    // (`**Problem**` → `**Solution**`), then the H1 title, so a FIX card's
    // Definition is never an empty "未记录故事原语". General: matches ANY FIX spec.
    if (out.narrative === undefined && (out.wish === undefined || out.wish === "")) {
      const fixWish = parseFixWish(spec);
      if (fixWish !== "") out.wish = fixWish;
    }
    // US-DOSSIER-003: Domain Model Context line.
    const ctx = /^[-*]\s*Context:\s*(.*)$/im.exec(spec);
    if (ctx !== null) out.context = (ctx[1] ?? "").trim();
    // US-DOSSIER-003 + FIX-334: AC checklist. Two on-disk shapes both feed the
    // same checklist: the US `**AC:**` bold block AND the FIX-format
    // `## Acceptance Criteria` (／`## 验收标准`) markdown section. Either opens
    // collection; the next bold section or markdown heading closes it.
    const acItems: { text: string; checked: boolean }[] = [];
    let inAc = false;
    for (const l of spec.split("\n")) {
      const t = l.trim();
      if (/^\*\*AC:?\*\*/i.test(t)) { inAc = true; continue; }
      if (/^#{1,6}\s*(Acceptance Criteria|验收标准|验收清单|AC)\s*$/i.test(t)) { inAc = true; continue; }
      if (inAc && (/^\*\*[A-Za-z一-鿿]/.test(t) || /^#{1,6}\s/.test(t))) break; // next bold/heading section ends the block
      const m = /^[-*]\s*\[([ xX])\]\s+(.*)$/.exec(t);
      if (inAc && m !== null) acItems.push({ checked: (m[1] ?? "").toLowerCase() === "x", text: (m[2] ?? "").trim() });
    }
    if (acItems.length > 0) out.acItems = acItems;
    // Design bullets under a 方案/Solution/Design markdown heading (US format).
    const design: string[] = [];
    let inDesign = false;
    for (const l of spec.split("\n")) {
      if (/^#{2,3}\s*(方案|Solution|Design)/i.test(l)) inDesign = true;
      else if (/^#{1,3}\s/.test(l)) inDesign = false;
      else if (inDesign) {
        const m = /^[-*]\s+(.*)$/.exec(l.trim());
        if (m !== null) design.push((m[1] ?? "").trim());
      }
    }
    // FIX-334: a FIX-format spec states its design as the `**Solution**:` (and
    // `**Root Cause**:`) bold lines, not a `## Solution` heading + bullets. When
    // the heading walk found nothing, fall back to those primitives so the Design
    // station carries the real fix approach instead of "尚未设计". General.
    if (design.length === 0) design.push(...parseFixDesign(spec));
    if (design.length > 0) out.design = design;
  } catch {
    /* no spec — bare card */
  }

  // ac-map.json → AC rows.
  try {
    const rows = JSON.parse(readFile(joinPath(dir, "ac-map.json"))) as Array<{
      ac?: string;
      status?: string;
      note?: string;
      verify?: string;
      tests?: string[];
      evidence?: unknown;
    }>;
    if (Array.isArray(rows)) {
      const acRows = rows
        .filter((r): r is NonNullable<typeof r> => r != null && typeof r.ac === "string" && typeof r.status === "string")
        .map((r) => {
          const verify = typeof r.verify === "string" ? r.verify.trim() : "";
          // FIX-282: ac-map evidence hrefs are run-dir-relative (`../acceptance/x`);
          // the story page sits at the story root, so re-base before rendering or
          // every `<img>` resolves to the wrong parent dir (404).
          const evidence = hydrateTextEvidence(dir, rebaseAcEvidenceToStoryRoot(parseAcEvidence(r.evidence)));
          return {
            ac: r.ac as string,
            status: r.status as string,
            ...(typeof r.note === "string" ? { note: r.note } : {}),
            ...(verify !== "" ? { verify } : {}),
            ...(Array.isArray(r.tests) && r.tests.length > 0 ? { tests: r.tests.filter((t) => typeof t === "string") } : {}),
            ...(evidence.length > 0 ? { evidence } : {}),
          };
        });
      if (acRows.length > 0) out.acRows = acRows;
    }
  } catch {
    /* no ac-map yet */
  }

  // US-DOSSIER-024: real image files under latest/screenshots → per-AC evidence
  // thumbnails + observable-gap detection. Best-effort; absent dir reads as none.
  try {
    const shotsDir = joinPath(dir, "latest", "screenshots");
    if (existsSync(shotsDir)) {
      const shots = readdirSync(shotsDir)
        .filter((f) => /\.(?:png|jpe?g|webp|gif)$/i.test(f))
        .sort()
        .map((f) => `latest/screenshots/${f}`);
      if (shots.length > 0) out.screenshotFiles = shots;
    }
  } catch {
    /* no screenshots dir */
  }

  // latest/<ID>-report.html → banner link.
  try {
    if (statDir(joinPath(dir, "latest", `${story.id}-report.html`))) out.reportHref = `latest/${story.id}-report.html`;
  } catch {
    /* no report */
  }

  // newest Review Score note → retrospective line. Card-local notes/ is the
  // home (US-META-008); the flat .roll/notes serves pre-migration history.
  try {
    const latest = readLatestStoryReviewScore(projectPath, story.id, dir);
    if (latest !== undefined) {
      out.reviewScore = {
        skill: latest.skill,
        score: latest.score,
        verdict: latest.verdict,
        ts: latest.ts,
        note: latest.note,
        ...(latest.href !== undefined ? { href: latest.href } : {}),
        ...(Object.keys(latest.dimensions).length > 0 ? { dimensions: latest.dimensions } : {}),
        // FIX-343 (AC6/AC9): carry provenance so the retrospective renders the
        // single peer Review Score block with the Reviewer + fresh session id;
        // a legacy `scoring: self` note renders in the muted not-gating style.
        ...(latest.scoring !== undefined ? { scoring: latest.scoring } : {}),
        ...(latest.scoredBy !== undefined ? { scoredBy: latest.scoredBy } : {}),
        ...(latest.sessionId !== undefined ? { sessionId: latest.sessionId } : {}),
        ...(latest.fallbackReason !== undefined ? { fallbackReason: latest.fallbackReason } : {}),
      };
      out.retro = [`score ${latest.score}`, `· ${latest.verdict}`, latest.note !== "" ? `— ${latest.note.slice(0, 240)}` : ""]
        .join(" ")
        .trim();
      searchableCardText += `\n${readFile(latest.sourcePath)}`;
    }
    const trend = cache !== undefined ? cache.reviewScoreTrend : readReviewScoreTrend(projectPath);
    if (trend !== undefined) out.reviewScoreTrend = trend;
  } catch {
    /* no notes */
  }

  // git history → tcr commits mentioning the story (oldest first).
  try {
    const subjects =
      gitFacts !== undefined
        ? gitFacts === null
          ? []
          : [...factsSubjects(gitFacts, story.id)].reverse()
        : execGit(projectPath, ["log", "--format=%s", "--fixed-strings", "--grep", story.id, "--reverse"]).split("\n");
    const commits = subjects
      .map((l) => l.trim())
      .filter((l) => l !== "")
      .slice(0, 40);
    if (commits.length > 0) out.commits = commits;
  } catch {
    /* not a git repo / git unavailable */
  }

  const executionRefs = collectExecutionRefs(projectPath, story.id, searchableCardText, gitFacts);
  if (executionRefs.length > 0) out.executionRefs = executionRefs;

  const deliveryEvidence = collectDeliveryEvidence(projectPath, story, searchableCardText, gitFacts);
  if (hasDeliveryEvidence(deliveryEvidence)) out.deliveryEvidence = deliveryEvidence;

  const dynamicEvidence = collectDynamicEvidence(projectPath, story);
  if (dynamicEvidence.length > 0) out.dynamicEvidence = dynamicEvidence;

  const peerReview = collectPeerReview(projectPath, story.id);
  if (peerReview !== undefined) out.peerReview = peerReview;

  const storyGraph = collectStoryGraph(projectPath, story, cache);
  if (hasStoryGraph(storyGraph)) out.storyGraph = storyGraph;

  const correctionActions = collectCorrectionActions(projectPath, story.id);
  if (correctionActions.length > 0) out.correctionActions = correctionActions;

  // US-DOSSIER-023: pre-derive the claimed→merged→attested rung from the SAME
  // truth sources the snapshot registry uses — the evidence flags on disk
  // (report / ac-map / screenshot) + the already-folded `delivered` merge signal
  // (truth selector + FIX-278 offline merge truth) — so the spine, banner, and
  // reconciliation panel read one deterministic ladder, never re-derived merge.
  const evidence = storyEvidenceFlags(projectPath, story);
  out.evidence = evidence;
  out.ladder = deriveDeliveryLadder(story, evidence);

  // US-OBS-034 — best-effort read the CycleRoleSummary for this story by
  // scanning cycle-logs directories for summary.json files that match storyId.
  try {
    const cycleLogsDir = joinPath(projectPath, '.roll', 'loop', 'cycle-logs');
    if (existsSync(cycleLogsDir)) {
      const candidates: Array<{ summary: CycleRoleSummary; summaryPath: string; cycleName: string; sortKey: number }> = [];
      const cycleDirs = readdirSync(cycleLogsDir, { withFileTypes: true })
        .filter((d) => d.isDirectory());
      for (const entry of cycleDirs) {
        const summaryPath = joinPath(cycleLogsDir, entry.name, 'summary.json');
        if (!existsSync(summaryPath)) continue;
        try {
          const raw = readFileSync(summaryPath, 'utf8');
          const summary = JSON.parse(raw) as CycleRoleSummary;
          if (summary.storyId === story.id) {
            const generatedAt = Date.parse(summary.generatedAt);
            const stat = statSync(summaryPath);
            candidates.push({
              summary,
              summaryPath,
              cycleName: entry.name,
              sortKey: Number.isFinite(generatedAt) ? generatedAt : stat.mtimeMs,
            });
          }
        } catch {
          // unparseable — skip this summary
        }
      }
      candidates.sort((a, b) => {
        if (b.sortKey !== a.sortKey) return b.sortKey - a.sortKey;
        return b.cycleName.localeCompare(a.cycleName);
      });
      const selected = candidates[0];
      if (selected !== undefined) {
        out.cycleRoleSummary = selected.summary;
        out.cycleRoleSummaryHref = relativePath(dir, selected.summaryPath);
        out.cycleRoleArtifactHrefs = cycleRoleArtifactHrefsFrom(dir, selected.summary);
      }
    }
  } catch {
    // cycle-logs unavailable — degrade gracefully
  }

  // US-BROW-009b: collect browser operations truth for this story.
  try {
    out.browserTruth = collectBrowserTruth({ projectPath, storyId: story.id });
  } catch {
    // browser facts unavailable — degrade gracefully
  }

  // US-BROW-013: collect the optional browser-operations timeline.
  try {
    out.browserTimeline = collectBrowserTimeline({ projectPath, storyId: story.id });
  } catch {
    // timeline facts unavailable — degrade gracefully
  }

  return out;
}

/**
 * US-DOSSIER-021 — the per-story evidence presence flags behind the ladder's
 * `attested` rung. Presence only, each from a real artifact on disk under the
 * card folder `.roll/features/<epic>/<ID>/` (reusing the SAME probe locations
 * the dossier collector already reads — `latest/<ID>-report.html`,
 * `ac-map.json`, `latest/screenshots/`):
 *   - `report`         — a `latest/<ID>-report.html` attest report exists.
 *   - `acMap`          — an `ac-map.json` exists for the story.
 *   - `visualEvidence` — at least one file under `latest/screenshots/`, OR a
 *     legacy screenshot-kind row in ac-map, OR a screenshot/cast/video evidence
 *     href in ac-map that resolves to a real artifact. Best-effort: a
 *     missing/unreadable source reads as the honest `false`.
 */
export function storyEvidenceFlags(projectPath: string, story: DossierStory): StoryEvidenceFlags {
  const dir = joinPath(projectPath, ".roll", "features", story.epic, story.id);
  let report = false;
  try {
    report = statSync(joinPath(dir, "latest", `${story.id}-report.html`)).isFile();
  } catch {
    /* no report */
  }
  const acMap = existsSync(joinPath(dir, "ac-map.json"));
  let visualEvidence = false;
  try {
    const screenshotsDir = joinPath(dir, "latest", "screenshots");
    visualEvidence = existsSync(screenshotsDir) && readdirSync(screenshotsDir).some((f) => f.trim() !== "");
  } catch {
    /* no screenshots dir */
  }
  if (!visualEvidence && acMap) {
    try {
      const rows = JSON.parse(readFile(joinPath(dir, "ac-map.json"))) as unknown;
      if (Array.isArray(rows)) {
        visualEvidence = rows.some((r) => acMapRowHasVisualEvidence(dir, r));
      }
    } catch {
      /* unreadable ac-map → no screenshot-kind signal */
    }
  }
  return { report, acMap, visualEvidence };
}

function acMapRowHasVisualEvidence(storyDir: string, row: unknown): boolean {
  if (row == null || typeof row !== "object") return false;
  const record = row as { kind?: unknown; evidence?: unknown };
  if (record.kind === "screenshot") return true; // historical compact shape
  return parseAcEvidence(record.evidence).some((e) => {
    if (e.kind !== "screenshot" && e.kind !== "cast" && e.kind !== "video") return false;
    if (e.href === undefined || e.href.trim() === "") return false;
    const href = rebaseEvidenceHrefToStoryRoot(e.href);
    if (/^[a-z]+:/i.test(href) || href.startsWith("/") || href.startsWith("#")) return false;
    return existsSync(joinPath(storyDir, href));
  });
}

function collectExecutionRefs(projectPath: string, storyId: string, text: string, gitFacts?: GitDossierFacts | null): ExecutionRef[] {
  const refs: ExecutionRef[] = [];
  const seen = new Set<string>();
  const add = (ref: ExecutionRef): void => {
    const key = `${ref.kind}:${ref.label}`;
    if (seen.has(key)) return;
    seen.add(key);
    refs.push(ref);
  };

  for (const match of text.matchAll(/\bPR\s*#?\s*(\d+)\b/gi)) {
    const pr = match[1];
    if (pr === undefined) continue;
    const start = Math.max(0, match.index - 120);
    const end = Math.min(text.length, match.index + 160);
    const nearby = text.slice(start, end);
    if (!/(merged|squash|合并|已合|CI\s*green|通过)/i.test(nearby)) continue;
    add({ kind: "merged-pr", label: `PR #${pr} merged`, ...commitCountFromText(nearby) });
  }

  try {
    for (const line of readFile(joinPath(projectPath, ".roll", "loop", "runs.jsonl")).split("\n")) {
      if (line.trim() === "") continue;
      const row = JSON.parse(line) as {
        story_id?: string;
        built?: unknown;
        status?: string;
        outcome?: string;
        cycle_id?: string;
        run_id?: string;
        tcr_count?: unknown;
      };
      const built = Array.isArray(row.built) && row.built.some((x) => x === storyId);
      if (row.story_id !== storyId && !built) continue;
      if (!rowDelivered(row as Record<string, unknown>)) continue; // US-TRUTH-004: selector-backed, no local literals
      const label = `cycle ${row.cycle_id ?? row.run_id ?? "delivered"}`;
      const n = typeof row.tcr_count === "number" && Number.isFinite(row.tcr_count) ? row.tcr_count : undefined;
      add({ kind: "cycle", label, ...(n !== undefined ? { commitCount: n } : {}) });
    }
  } catch {
    /* no loop rows */
  }

  return refs.slice(0, 20);
}

function commitCountFromText(text: string): { commitCount?: number } {
  const m = /(\d+)\s*(?:commits?|TCR commits?|micro-commits?|个\s*(?:TCR\s*)?提交|个\s*TCR)/i.exec(text);
  if (m?.[1] === undefined) return {};
  const n = Number(m[1]);
  return Number.isFinite(n) ? { commitCount: n } : {};
}

interface RunRow {
  run_id?: string;
  cycle_id?: string;
  story_id?: string;
  built?: unknown;
  status?: string;
  outcome?: string;
  agent?: string;
  ts?: string;
  duration_sec?: number;
  cost_usd?: number;
  tokens_in?: number;
  tokens_out?: number;
}

interface EventRow {
  type?: string;
  storyId?: string;
  cycleId?: string;
  prNumber?: number;
  agent?: string;
  peer?: string;
  verdict?: string;
  findings?: number;
  cost?: number;
  stage?: string;
  action?: string;
  plannedAction?: string;
  signal?: string;
  reason?: string;
  mode?: string;
  source?: string;
  targetId?: string;
  ts?: number;
}

function collectDeliveryEvidence(projectPath: string, story: DossierStory, text: string, gitFacts?: GitDossierFacts | null): DeliveryEvidence {
  const prs = new Map<number, DeliveryPrEvidence>();
  const files = new Set<string>();
  const timeline: DeliveryTimelineEntry[] = [];
  let diffHref: string | undefined;
  let agent: string | undefined;
  let cost: DeliveryCostEvidence | undefined;

  const addPr = (number: number, patch: Omit<DeliveryPrEvidence, "number"> = {}): void => {
    if (!Number.isFinite(number)) return;
    const cur = prs.get(number) ?? { number };
    if (patch.href !== undefined && cur.href === undefined) cur.href = patch.href;
    if (patch.ci !== undefined) cur.ci = patch.ci;
    prs.set(number, cur);
  };
  const addTimeline = (label: string, at: string | undefined): void => {
    if (at === undefined || at === "") return;
    if (timeline.some((t) => t.label === label)) return;
    timeline.push({ label, at });
  };

  if (story.created !== undefined && story.created !== "") addTimeline("definition", story.created);

  for (const match of text.matchAll(/https:\/\/github\.com\/[A-Za-z0-9_.-]+\/[A-Za-z0-9_.-]+\/pull\/(\d+)(?:\/files|\.diff|\.patch)?/g)) {
    const raw = match[0];
    const n = numberFromString(match[1]);
    if (n === undefined) continue;
    const href = raw.replace(/(?:\/files|\.diff|\.patch)$/, "");
    addPr(n, { href, ...ciPatch(nearbyText(text, match.index, 120, 160)) });
    if (/\/files$|\.diff$|\.patch$/.test(raw)) diffHref = raw;
    else if (diffHref === undefined) diffHref = `${href}/files`;
  }

  for (const match of text.matchAll(/\bPR\s*#?\s*(\d+)\b/gi)) {
    const n = numberFromString(match[1]);
    if (n === undefined) continue;
    addPr(n, ciPatch(nearbyText(text, match.index, 120, 160)));
  }
  const prNums =
    gitFacts !== undefined
      ? gitFacts === null
        ? []
        : factsPrNumbers(gitFacts, story.id)
      : gitPrNumbers(projectPath, story.id);
  for (const n of prNums) addPr(n);

  const explicitDiff = /(?:^|\n)\s*(?:Diff|PR diff|差异|改动\s*diff)\s*[:：]\s*(https?:\/\/\S+)/i.exec(text);
  if (explicitDiff?.[1] !== undefined) diffHref = explicitDiff[1].trim();

  for (const line of text.split("\n")) {
    const m = /^\s*(?:[-*]\s*)?(?:Files changed|Changed files|files-changed|改动文件|文件清单)\s*[:：]\s*(.+)$/i.exec(line);
    if (m?.[1] === undefined) continue;
    for (const f of splitFiles(m[1])) files.add(f);
  }

  const runs = readRunRows(projectPath, story.id);
  const deliveredRuns = runs.filter((r) => runMatchesStory(r, story.id) && isDeliveredRun(r));
  const latestRun = deliveredRuns[deliveredRuns.length - 1];
  if (latestRun !== undefined) {
    if (latestRun.agent !== undefined && latestRun.agent !== "") agent = latestRun.agent;
    cost = costFromRun(latestRun);
    addTimeline("delivery", latestRun.ts);
  }

  const changed =
    gitFacts !== undefined
      ? gitFacts === null
        ? []
        : factsChangedFiles(gitFacts, story.id)
      : gitChangedFiles(projectPath, story.id);
  for (const f of changed) files.add(f);
  const slug = gitFacts !== undefined ? gitFacts?.slug : githubSlug(projectPath);
  if (slug !== undefined) {
    for (const p of prs.values()) if (p.href === undefined) p.href = `https://github.com/${slug}/pull/${p.number}`;
  }
  if (diffHref === undefined) {
    const firstPr = [...prs.values()].find((p) => p.href !== undefined);
    if (firstPr?.href !== undefined) diffHref = `${firstPr.href}/files`;
  }

  const knownCycles = new Set(deliveredRuns.flatMap((r) => [r.cycle_id, r.run_id].filter((x): x is string => typeof x === "string" && x !== "")));
  const knownPrs = (): Set<number> => new Set([...prs.keys()]);
  for (const ev of readEventRows(projectPath)) {
    const sameStory = ev.storyId === story.id || (ev.cycleId !== undefined && knownCycles.has(ev.cycleId));
    if (ev.type === "cycle:start" && sameStory) {
      addTimeline("execution", isoFromEventTs(ev.ts));
      if (agent === undefined && ev.agent !== undefined && ev.agent !== "") agent = ev.agent;
    }
    if (ev.type === "pr:merge" && ev.prNumber !== undefined && sameStory) {
      addPr(ev.prNumber);
      addTimeline("delivery", isoFromEventTs(ev.ts));
    }
    if ((ev.type === "ci:pass" || ev.type === "ci:fail") && ev.prNumber !== undefined && knownPrs().has(ev.prNumber)) {
      addPr(ev.prNumber, { ci: ev.type === "ci:pass" ? "green" : "red" });
    }
  }

  const out: DeliveryEvidence = {};
  const prRows = [...prs.values()].sort((a, b) => a.number - b.number);
  if (prRows.length > 0) out.prs = prRows;
  if (diffHref !== undefined) out.diffHref = diffHref;
  const fileRows = [...files].sort();
  if (fileRows.length > 0) out.filesChanged = fileRows.slice(0, 40);
  if (agent !== undefined) out.agent = agent;
  if (cost !== undefined) out.cost = cost;
  if (timeline.length > 0) out.timeline = sortTimeline(timeline);
  return out;
}

function collectDynamicEvidence(projectPath: string, story: DossierStory): DynamicEvidence[] {
  const dir = joinPath(projectPath, ".roll", "features", story.epic, story.id, "latest");
  const out: DynamicEvidence[] = [];
  const add = (item: DynamicEvidence): void => {
    if (out.some((x) => x.href === item.href)) return;
    out.push(item);
  };
  try {
    const evidenceDir = joinPath(dir, "evidence");
    if (existsSync(evidenceDir)) {
      for (const file of readdirSync(evidenceDir).sort()) {
        if (!/\.(?:cast|asciinema)$/i.test(file)) continue;
        add({ kind: "cast", label: file, href: `latest/evidence/${file}` });
      }
    }
  } catch {
    /* no dynamic evidence */
  }
  try {
    const screenshotsDir = joinPath(dir, "screenshots");
    if (existsSync(screenshotsDir)) {
      for (const file of readdirSync(screenshotsDir).sort()) {
        if (!/\.(?:mp4|webm|mov|gif)$/i.test(file)) continue;
        add({ kind: "video", label: file, href: `latest/screenshots/${file}` });
      }
    }
  } catch {
    /* no video evidence */
  }
  return out.slice(0, 12);
}

interface StorySpecRef {
  id: string;
  epic: string;
  storyDir: string;
  specPath: string;
}

const STORY_ID_PATTERN = "\\b(?:US|FIX|REFACTOR|IDEA)(?:-[A-Z0-9]+)*-\\d+[a-z]?\\b";

function collectStoryGraph(projectPath: string, story: DossierStory, cache?: DossierRunCache): StoryGraph {
  const refs = cache !== undefined ? cache.specRefs : scanStorySpecs(projectPath);
  const byId = new Map(refs.map((ref) => [ref.id, ref]));
  const current = byId.get(story.id) ?? {
    id: story.id,
    epic: story.epic,
    storyDir: joinPath(projectPath, ".roll", "features", story.epic, story.id),
    specPath: joinPath(projectPath, ".roll", "features", story.epic, story.id, "spec.md"),
  };
  let currentSpec = "";
  try {
    currentSpec = readFile(current.specPath);
  } catch {
    currentSpec = "";
  }

  const dependsOn = storyGraphLinks(extractDependsOnIds(currentSpec).filter((id) => id !== story.id), story, byId);
  const reverseIds =
    cache !== undefined
      ? refs.filter((r) => r.id !== story.id && (cache.dependsOnById.get(r.id) ?? []).includes(story.id)).map((r) => r.id)
      : reverseDependencyIds(refs, story.id);
  const dependedBy = storyGraphLinks(reverseIds, story, byId);
  const fixes =
    story.id.startsWith("FIX-") || story.type === "FIX"
      ? storyGraphLinks(extractFixesIds(currentSpec).filter((id) => id !== story.id), story, byId)
      : [];
  const release = collectReleaseTrace(projectPath, story.id);

  const graph: StoryGraph = {};
  if (dependsOn.length > 0) graph.dependsOn = dependsOn;
  if (dependedBy.length > 0) graph.dependedBy = dependedBy;
  if (fixes.length > 0) graph.fixes = fixes;
  if (release !== undefined) graph.release = release;
  return graph;
}

function scanStorySpecs(projectPath: string): StorySpecRef[] {
  const featuresDir = joinPath(projectPath, ".roll", "features");
  const refs: StorySpecRef[] = [];
  try {
    for (const epicEntry of readdirSync(featuresDir, { withFileTypes: true }).sort((a, b) => a.name.localeCompare(b.name))) {
      if (!epicEntry.isDirectory()) continue;
      const epicDir = joinPath(featuresDir, epicEntry.name);
      for (const storyEntry of readdirSync(epicDir, { withFileTypes: true }).sort((a, b) => a.name.localeCompare(b.name))) {
        if (!storyEntry.isDirectory()) continue;
        const specPath = joinPath(epicDir, storyEntry.name, "spec.md");
        if (!existsSync(specPath)) continue;
        refs.push({ id: storyEntry.name, epic: epicEntry.name, storyDir: joinPath(epicDir, storyEntry.name), specPath });
      }
    }
  } catch {
    return [];
  }
  return refs;
}

function extractDependsOnIds(spec: string): string[] {
  const ids: string[] = [];
  for (const line of spec.split("\n")) {
    if (!/\bdepends-on\b\s*[:：]/i.test(line)) continue;
    for (const id of storyIdsFromText(line)) if (!ids.includes(id)) ids.push(id);
  }
  return ids;
}

function extractFixesIds(spec: string): string[] {
  const ids: string[] = [];
  for (const line of spec.split("\n")) {
    if (!/\bfix(?:es|ed)?\b\s*[:：]?|修复|所修上游/i.test(line)) continue;
    for (const id of storyIdsFromText(line)) {
      if (!id.startsWith("US-") || ids.includes(id)) continue;
      ids.push(id);
    }
  }
  return ids;
}

function reverseDependencyIds(refs: readonly StorySpecRef[], storyId: string): string[] {
  const out: string[] = [];
  for (const ref of refs) {
    if (ref.id === storyId) continue;
    let spec = "";
    try {
      spec = readFile(ref.specPath);
    } catch {
      continue;
    }
    if (!extractDependsOnIds(spec).includes(storyId)) continue;
    if (!out.includes(ref.id)) out.push(ref.id);
  }
  return out;
}

function storyIdsFromText(text: string): string[] {
  const ids: string[] = [];
  const re = new RegExp(STORY_ID_PATTERN, "g");
  for (const match of text.matchAll(re)) {
    const id = match[0];
    if (!ids.includes(id)) ids.push(id);
  }
  return ids;
}

function storyGraphLinks(ids: readonly string[], story: DossierStory, byId: ReadonlyMap<string, StorySpecRef>): StoryGraphLink[] {
  return ids.map((id) => {
    const href = storyIndexHref(story, id, byId);
    return href !== undefined ? { id, href } : { id };
  });
}

function storyIndexHref(story: DossierStory, targetId: string, byId: ReadonlyMap<string, StorySpecRef>): string | undefined {
  const target = byId.get(targetId);
  if (target === undefined) return undefined;
  if (!existsSync(joinPath(target.storyDir, "index.html"))) return undefined;
  if (target.epic === story.epic) return `../${target.id}/index.html`;
  return `../../${target.epic}/${target.id}/index.html`;
}

function collectReleaseTrace(projectPath: string, storyId: string): StoryReleaseTrace | undefined {
  let changelog = "";
  try {
    changelog = readFile(joinPath(projectPath, "CHANGELOG.md"));
  } catch {
    return undefined;
  }
  let heading: string | undefined;
  const storyRe = new RegExp(`\\b${escapeRegExp(storyId)}\\b`);
  for (const line of changelog.split("\n")) {
    const h = /^##+\s+(.+?)\s*$/.exec(line);
    if (h?.[1] !== undefined) heading = stripMarkdownLink(h[1].trim());
    if (heading === undefined || !storyRe.test(line)) continue;
    return { label: heading, href: `../../../../CHANGELOG.md#${markdownAnchor(heading)}` };
  }
  return undefined;
}

function stripMarkdownLink(text: string): string {
  return text.replace(/\[([^\]]+)\]\([^)]+\)/g, "$1");
}

function markdownAnchor(text: string): string {
  return text
    .trim()
    .toLowerCase()
    .replace(/[`~!@#$%^&*()+=[\]{}|;:'",.<>/?\\]/g, "")
    .replace(/\s+/g, "-")
    .replace(/-+/g, "-")
    .replace(/^-|-$/g, "");
}

function escapeRegExp(text: string): string {
  return text.replace(/[.*+?^${}()|[\]\\]/g, "\\$&");
}

function sortTimeline(timeline: DeliveryTimelineEntry[]): DeliveryTimelineEntry[] {
  const stageOrder = new Map([
    ["definition", 0],
    ["design", 1],
    ["execution", 2],
    ["delivery", 3],
    ["retrospective", 4],
  ]);
  return [...timeline].sort((a, b) => {
    const ao = stageOrder.get(a.label) ?? 100;
    const bo = stageOrder.get(b.label) ?? 100;
    if (ao !== bo) return ao - bo;
    return a.at.localeCompare(b.at);
  });
}

function nearbyText(text: string, index: number | undefined, before: number, after: number): string {
  const i = index ?? 0;
  return text.slice(Math.max(0, i - before), Math.min(text.length, i + after));
}

function numberFromString(s: string | undefined): number | undefined {
  if (s === undefined) return undefined;
  const n = Number(s);
  return Number.isInteger(n) && n > 0 ? n : undefined;
}

function ciPatch(text: string): { ci?: CiVerdict } {
  if (/(CI|check|status).{0,32}(green|pass|passed|success|successful|绿|通过|成功)/i.test(text)) return { ci: "green" };
  if (/(CI|check|status).{0,32}(red|fail|failed|failure|红|失败)/i.test(text)) return { ci: "red" };
  if (/(no CI|CI none|无 CI|没有 CI)/i.test(text)) return { ci: "none" };
  return {};
}

function splitFiles(s: string): string[] {
  return s
    .split(/[,，;；]/)
    .map((f) => f.trim())
    .filter((f) => f !== "" && !/\s/.test(f))
    .slice(0, 80);
}

function readRunRows(projectPath: string, storyId: string): RunRow[] {
  try {
    return readFile(joinPath(projectPath, ".roll", "loop", "runs.jsonl"))
      .split("\n")
      .map((line) => line.trim())
      .filter((line) => line !== "")
      .map((line) => JSON.parse(line) as unknown)
      .filter((row): row is RunRow => isRunRow(row) && runMatchesStory(row, storyId));
  } catch {
    return [];
  }
}

function isRunRow(row: unknown): row is RunRow {
  return typeof row === "object" && row !== null;
}

function runMatchesStory(row: RunRow, storyId: string): boolean {
  return row.story_id === storyId || (Array.isArray(row.built) && row.built.some((x) => x === storyId));
}

function isDeliveredRun(row: RunRow): boolean {
  // US-TRUTH-004: one adapter, no per-consumer literals — published/built
  // (delivery pending merge) count exactly where pre-FIX-244 "done" counted.
  return rowDelivered(row as Record<string, unknown>);
}

function costFromRun(row: RunRow): DeliveryCostEvidence | undefined {
  const cost: DeliveryCostEvidence = {};
  if (typeof row.cost_usd === "number" && Number.isFinite(row.cost_usd)) cost.usd = row.cost_usd;
  if (typeof row.tokens_in === "number" && Number.isFinite(row.tokens_in)) cost.tokensIn = row.tokens_in;
  if (typeof row.tokens_out === "number" && Number.isFinite(row.tokens_out)) cost.tokensOut = row.tokens_out;
  return Object.keys(cost).length > 0 ? cost : undefined;
}

function readEventRows(projectPath: string): EventRow[] {
  try {
    return readFile(joinPath(projectPath, ".roll", "loop", "events.ndjson"))
      .split("\n")
      .map((line) => line.trim())
      .filter((line) => line !== "")
      .map((line) => parseEventLine(line) as unknown)
      .filter((row): row is EventRow => isEventRow(row));
  } catch {
    return [];
  }
}

function collectCorrectionActions(projectPath: string, storyId: string): CorrectionTraceEntry[] {
  const out: CorrectionTraceEntry[] = [];
  for (const ev of readEventRows(projectPath)) {
    if (ev.type !== "correction:action" || ev.storyId !== storyId) continue;
    if (ev.action === undefined || ev.signal === undefined || ev.reason === undefined) continue;
    const at = isoFromEventTs(ev.ts);
    if (at === undefined) continue;
    out.push({
      action: ev.action,
      signal: ev.signal,
      reason: ev.reason,
      at,
      ...(ev.mode !== undefined ? { mode: ev.mode } : {}),
      ...(ev.source !== undefined ? { source: ev.source } : {}),
      ...(ev.targetId !== undefined ? { targetId: ev.targetId } : {}),
    });
  }
  return out.sort((a, b) => a.at.localeCompare(b.at)).slice(-20);
}

interface PeerReviewRecord {
  cycleId: string;
  verdict: PeerReviewVerdict;
  findings: string[];
  sourceOrder: number;
  source: string;
  peer?: string;
  stage?: string;
  href?: string;
}

function collectPeerReview(projectPath: string, storyId: string): PeerReviewEvidence | undefined {
  const cycles = storyCycleIds(projectPath, storyId);
  if (cycles.length === 0) return undefined;
  const records: PeerReviewRecord[] = [];
  const seen = new Set<string>();
  const add = (r: PeerReviewRecord): void => {
    const key = `${r.cycleId}:${r.stage ?? ""}:${r.peer ?? ""}:${r.verdict}:${r.source}`;
    if (seen.has(key)) return;
    seen.add(key);
    records.push(r);
  };

  const peerDir = joinPath(projectPath, ".roll", "loop", "peer");
  if (existsSync(peerDir)) {
    try {
      const files = readdirSync(peerDir)
        .filter((f) => cycles.some((cycle) => f.startsWith(`cycle-${cycle}.`)))
        .sort();
      files.forEach((file, index) => {
        const cycleId = cycles.find((cycle) => file.startsWith(`cycle-${cycle}.`));
        if (cycleId === undefined) return;
        const parsed = parsePeerRecordFile(joinPath(peerDir, file), cycleId, index, `../../../loop/peer/${file}`);
        if (parsed !== undefined) add(parsed);
      });
    } catch {
      /* peer dir unreadable */
    }
  }

  for (const ev of readEventRows(projectPath)) {
    if (ev.type !== "pair:verdict" || ev.cycleId === undefined || !cycles.includes(ev.cycleId)) continue;
    const verdict = normalizePeerVerdict(ev.verdict);
    if (verdict === undefined) continue;
    const findings =
      typeof ev.findings === "number" && Number.isFinite(ev.findings) && ev.findings > 0
        ? [`${ev.findings} findings`]
        : [];
    add({
      cycleId: ev.cycleId,
      verdict,
      findings,
      sourceOrder: 10_000 + records.length,
      source: "event",
      ...(ev.peer !== undefined ? { peer: ev.peer } : {}),
      ...(ev.stage !== undefined ? { stage: ev.stage } : {}),
    });
  }

  const sorted = records.sort((a, b) => {
    const ac = cycles.indexOf(a.cycleId);
    const bc = cycles.indexOf(b.cycleId);
    if (ac !== bc) return ac - bc;
    const as = peerStageOrder(a.stage);
    const bs = peerStageOrder(b.stage);
    if (as !== bs) return as - bs;
    return a.sourceOrder - b.sourceOrder;
  });
  if (sorted.length === 0) return undefined;
  const rounds = sorted.map((r, i) => ({
    round: i + 1,
    verdict: r.verdict,
    findings: r.findings,
    ...(r.peer !== undefined ? { peer: r.peer } : {}),
    ...(r.stage !== undefined ? { stage: r.stage } : {}),
    ...(r.href !== undefined ? { href: r.href } : {}),
  }));
  const final = rounds[rounds.length - 1]?.verdict;
  return final !== undefined ? { finalVerdict: final, rounds } : undefined;
}

function storyCycleIds(projectPath: string, storyId: string): string[] {
  const out: string[] = [];
  const add = (id: string | undefined): void => {
    if (id === undefined || id === "" || out.includes(id)) return;
    out.push(id);
  };
  for (const row of readRunRows(projectPath, storyId)) {
    if (!runMatchesStory(row, storyId)) continue;
    add(row.cycle_id);
    add(row.run_id);
  }
  for (const ev of readEventRows(projectPath)) {
    if (ev.storyId === storyId) add(ev.cycleId);
  }
  return out;
}

function parsePeerRecordFile(path: string, cycleId: string, sourceOrder: number, href: string): PeerReviewRecord | undefined {
  let text: string;
  try {
    text = readFile(path);
  } catch {
    return undefined;
  }
  if (path.endsWith(".json")) {
    try {
      const obj = JSON.parse(text) as Record<string, unknown>;
      const verdict = normalizePeerVerdict(obj["verdict"]);
      if (verdict === undefined) return undefined;
      const findingsRaw = obj["findings"];
      const findings = Array.isArray(findingsRaw)
        ? findingsRaw.filter((x): x is string => typeof x === "string" && x.trim() !== "").map((x) => x.trim()).slice(0, 8)
        : [];
      return {
        cycleId,
        verdict,
        findings,
        sourceOrder,
        source: path,
        href,
        ...(typeof obj["peer"] === "string" && obj["peer"] !== "" ? { peer: obj["peer"] } : {}),
        ...(typeof obj["stage"] === "string" && obj["stage"] !== "" ? { stage: obj["stage"] } : {}),
      };
    } catch {
      return undefined;
    }
  }
  const verdict = normalizePeerVerdict(text);
  if (verdict === undefined) return undefined;
  const peer = /^peer\s*[:：]\s*(\S+)/im.exec(text)?.[1];
  const stage = /^stage\s*[:：]\s*(\S+)/im.exec(text)?.[1];
  const findings = text
    .split("\n")
    .map((line) => /^[-*]\s+(.*)$/.exec(line.trim())?.[1]?.trim())
    .filter((line): line is string => line !== undefined && line !== "")
    .slice(0, 8);
  return {
    cycleId,
    verdict,
    findings,
    sourceOrder,
    source: path,
    href,
    ...(peer !== undefined && peer !== "" ? { peer } : {}),
    ...(stage !== undefined && stage !== "" ? { stage } : {}),
  };
}

function normalizePeerVerdict(value: unknown): PeerReviewVerdict | undefined {
  const s = typeof value === "string" ? value : "";
  const m = /\b(agree|refine|object|escalate)\b/i.exec(s);
  if (m?.[1] === undefined) return undefined;
  return m[1].toUpperCase() as PeerReviewVerdict;
}

function peerStageOrder(stage: string | undefined): number {
  if (stage === "design") return 0;
  if (stage === "code") return 1;
  if (stage === "cycle") return 2;
  return 10;
}

function isEventRow(row: unknown): row is EventRow {
  if (typeof row !== "object" || row === null) return false;
  const r = row as Record<string, unknown>;
  return typeof r["type"] === "string";
}

function isoFromEventTs(ts: number | undefined): string | undefined {
  if (ts === undefined || !Number.isFinite(ts)) return undefined;
  const ms = ts > 10_000_000_000 ? ts : ts * 1000;
  return new Date(ms).toISOString();
}

function gitChangedFiles(projectPath: string, storyId: string): string[] {
  try {
    return execGit(projectPath, ["log", "--name-only", "--pretty=format:", "--fixed-strings", "--grep", storyId])
      .split("\n")
      .map((l) => l.trim())
      .filter((l) => l !== "" && !l.includes(" "))
      .slice(0, 80);
  } catch {
    return [];
  }
}

function gitPrNumbers(projectPath: string, storyId: string): number[] {
  try {
    const nums = new Set<number>();
    for (const subject of execGit(projectPath, ["log", "--format=%s", "--fixed-strings", "--grep", storyId]).split("\n")) {
      for (const match of subject.matchAll(/(?:\(#|PR\s*#?)(\d+)\)?/gi)) {
        const n = numberFromString(match[1]);
        if (n !== undefined) nums.add(n);
      }
    }
    return [...nums];
  } catch {
    return [];
  }
}

function githubSlug(projectPath: string): string | undefined {
  try {
    const remote = execGit(projectPath, ["config", "--get", "remote.origin.url"]).trim();
    const https = /^https:\/\/github\.com\/([^/]+\/[^/.]+)(?:\.git)?$/.exec(remote);
    if (https?.[1] !== undefined) return https[1];
    const ssh = /^git@github\.com:([^/]+\/[^/.]+)(?:\.git)?$/.exec(remote);
    if (ssh?.[1] !== undefined) return ssh[1];
    return undefined;
  } catch {
    return undefined;
  }
}

// ── FIX-275: one-spawn git facts snapshot ────────────────────────────────────
// Profiling `roll index` showed 55% of wall-clock in per-card
// `git log --grep` spawns (~3 per card × ~640 cards). One full-history pass
// captures everything those greps read; per-card resolution becomes string
// matching over the snapshot with IDENTICAL semantics (--fixed-strings --grep
// matches anywhere in the full commit message; default order newest-first).

export interface GitDossierFacts {
  /** Commits newest-first: subject, full message, changed files (name-only). */
  commits: Array<{ subject: string; message: string; files: string[] }>;
  slug: string | undefined;
}

/** One `git log` spawn for the whole dossier run; null when not a git repo. */
export function collectGitDossierFacts(projectPath: string): GitDossierFacts | null {
  let raw: string;
  try {
    const ref = gitDossierLogRef(projectPath);
    raw = execGit(projectPath, ["log", ref, "--name-only", "--pretty=format:%x01%s%x02%B%x03"]);
  } catch {
    return null;
  }
  const commits: GitDossierFacts["commits"] = [];
  for (const rec of raw.split("\u0001")) {
    if (rec.trim() === "") continue;
    const subjEnd = rec.indexOf("\u0002");
    const bodyEnd = rec.indexOf("\u0003");
    if (subjEnd < 0 || bodyEnd < 0) continue;
    const subject = rec.slice(0, subjEnd);
    const message = rec.slice(subjEnd + 1, bodyEnd);
    const files = rec
      .slice(bodyEnd + 1)
      .split("\n")
      .map((l) => l.trim())
      .filter((l) => l !== "");
    commits.push({ subject, message, files });
  }
  return { commits, slug: githubSlug(projectPath) };
}

function gitDossierLogRef(projectPath: string): string {
  // E1: the dossier's git-log ref is the project's configured integration branch
  // (default origin/main); falls back to HEAD when the ref does not resolve.
  const integrationBranch = resolveIntegrationBranch(projectPath);
  try {
    execGit(projectPath, ["rev-parse", "--verify", "--quiet", `${integrationBranch}^{commit}`]);
    return integrationBranch;
  } catch {
    return "HEAD";
  }
}

/**
 * FIX-275 — run-scoped shared facts for a whole dossier regeneration. Profiling
 * showed three per-card O(all-cards) reads: ~3 git spawns, a full notes-tree
 * scan for the project-wide review-score trend, and a full spec read for reverse
 * dependencies. Build once per run; per-card collection becomes lookups. The
 * single-card path (attest) simply omits the cache and keeps live reads.
 */
export interface DossierRunCache {
  git: GitDossierFacts | null;
  reviewScoreTrend: string | undefined;
  specRefs: StorySpecRef[];
  /** id → the ids its spec declares under depends-on. */
  dependsOnById: Map<string, string[]>;
  /** id → PR numbers explicitly linked from the story spec. */
  prNumbersById: Map<string, number[]>;
}

export function buildDossierRunCache(projectPath: string): DossierRunCache {
  const specRefs = scanStorySpecs(projectPath);
  const dependsOnById = new Map<string, string[]>();
  const prNumbersById = new Map<string, number[]>();
  for (const ref of specRefs) {
    let spec = "";
    try {
      spec = readFile(ref.specPath);
    } catch {
      /* unreadable spec → no deps */
    }
    dependsOnById.set(ref.id, extractDependsOnIds(spec));
    prNumbersById.set(ref.id, extractSpecPrNumbers(spec));
  }
  return {
    git: collectGitDossierFacts(projectPath),
    reviewScoreTrend: readReviewScoreTrend(projectPath),
    specRefs,
    dependsOnById,
    prNumbersById,
  };
}

/** Newest-first commits whose full message mentions the id (≡ --fixed-strings --grep). */
function factsCommitsFor(facts: GitDossierFacts, storyId: string): GitDossierFacts["commits"] {
  return facts.commits.filter((c) => c.message.includes(storyId) || c.subject.includes(storyId));
}

function factsSubjects(facts: GitDossierFacts, storyId: string): string[] {
  return factsCommitsFor(facts, storyId).map((c) => c.subject);
}

function factsChangedFiles(facts: GitDossierFacts, storyId: string): string[] {
  return factsCommitsFor(facts, storyId)
    .flatMap((c) => c.files)
    .map((l) => l.trim())
    .filter((l) => l !== "" && !l.includes(" "))
    .slice(0, 80);
}

/** FIX-278: durable, offline merge truth. `collectGitDossierFacts` runs a plain
 *  `git log` (current branch only), so every commit it returns is already
 *  reachable from HEAD — i.e. merged. A story counts as merged when either:
 *    1. a commit SUBJECT names the id — the story's own work landed (`tcr: US-X …`,
 *       `Story US-X: … (#N)`); a bare depends-on mention lives in a body, not a
 *       subject, so this does not over-promote a still-open dependant, or
 *    2. a `(#N)` / `PR #N` PR-merge commit references the id (e.g. a loop-cycle
 *       squash whose subject carries `(#N)` and whose body names the story).
 *  The rebuild path feeds this to collectDossier so an already-merged card keeps
 *  its delivered state without a live PR-evidence snapshot. */
export function storyHasMergeEvidence(facts: GitDossierFacts | null, storyId: string): boolean {
  if (facts === null) return false;
  if (facts.commits.some((c) => c.subject.includes(storyId))) return true;
  return factsPrNumbers(facts, storyId).length > 0;
}

/**
 * FIX-348: merge truth BY PR NUMBER, independent of the story-id. The FIX-347
 * reconcile only matched commits that NAME the story (`storyHasMergeEvidence`),
 * so a merged delivery whose squash subject carries `(#N)` but NOT the id stayed
 * yellow forever — e.g. FIX-287 / PR #773 landed as `tcr: align machine page
 * typography (#773)`, which names neither FIX-287 nor any story. The cycle's
 * recorded PR number (from its `cycle:terminal` twin) is the missing key: if
 * main's git log (origin/main, every commit already merged) carries a `(#N)`
 * PR-merge commit for that exact number, the delivery landed — regardless of
 * whether the subject names the story.
 *
 * RED LINE: only an actually-merged `(#N)` commit on main counts. An OPEN or
 * closed-unmerged PR leaves no such commit in the merged history, so this stays
 * false and the row stays pending — the open PR number alone never promotes.
 */
export function gitHasPrMergeCommit(facts: GitDossierFacts | null, prNumber: number): boolean {
  if (facts === null || !Number.isInteger(prNumber) || prNumber <= 0) return false;
  // Reuse the proven `(#N)` / `PR #N` extraction (factsPrNumbers' regex), then
  // match the exact captured number — no fragile digit-boundary regex (e.g.
  // `(#773)` must NOT match the row's PR #77 or PR #7730).
  for (const c of facts.commits) {
    for (const m of c.subject.matchAll(/(?:\(#|PR\s*#?)(\d+)\)?/gi)) {
      if (numberFromString(m[1]) === prNumber) return true;
    }
  }
  return false;
}

export function storyHasSpecPrMergeEvidence(cache: Pick<DossierRunCache, "git" | "prNumbersById">, storyId: string): boolean {
  const prs = cache.prNumbersById.get(storyId) ?? [];
  return prs.some((pr) => gitHasPrMergeCommit(cache.git, pr));
}

function factsPrNumbers(facts: GitDossierFacts, storyId: string): number[] {
  const nums = new Set<number>();
  for (const subject of factsSubjects(facts, storyId)) {
    for (const match of subject.matchAll(/(?:\(#|PR\s*#?)(\d+)\)?/gi)) {
      const n = numberFromString(match[1]);
      if (n !== undefined) nums.add(n);
    }
  }
  return [...nums];
}

function extractSpecPrNumbers(spec: string): number[] {
  const nums = new Set<number>();
  for (const match of spec.matchAll(/github\.com\/[^\s)]+\/[^\s)]+\/pull\/(\d+)\b/gi)) {
    const n = numberFromString(match[1]);
    if (n !== undefined) nums.add(n);
  }
  for (const match of spec.matchAll(/\bPR\s*#?(\d+)\b/gi)) {
    const n = numberFromString(match[1]);
    if (n !== undefined) nums.add(n);
  }
  return [...nums].sort((a, b) => a - b);
}

/**
 * US-DOSSIER-024 — normalize an ac-map `evidence` field into typed AcEvidence
 * rows. Tolerant of malformed shapes (FIX-258/US-ATTEST-010 carry
 * `{ kind, label, href }` for screenshots and `{ kind, label, textFile }` for
 * text); a `textFile` is folded into `href`. Unknown/absent kinds drop.
 */
export function parseAcEvidence(raw: unknown): AcEvidence[] {
  if (!Array.isArray(raw)) return [];
  const out: AcEvidence[] = [];
  for (const e of raw) {
    if (e == null || typeof e !== "object") continue;
    const o = e as { kind?: unknown; label?: unknown; href?: unknown; textFile?: unknown };
    const kind = o.kind;
    if (kind !== "screenshot" && kind !== "text" && kind !== "cast" && kind !== "video") continue;
    const href = typeof o.href === "string" && o.href.trim() !== "" ? o.href.trim() : typeof o.textFile === "string" && o.textFile.trim() !== "" ? o.textFile.trim() : undefined;
    const label = typeof o.label === "string" && o.label.trim() !== "" ? o.label.trim() : undefined;
    out.push({ kind, ...(label !== undefined ? { label } : {}), ...(href !== undefined ? { href } : {}) });
  }
  return out;
}

/**
 * FIX-282 — re-base a run-dir-relative evidence href so it resolves from the
 * STORY ROOT (`features/<epic>/<id>/index.html`), not from the run dir
 * (`<ts>/<id>-report.html`).
 *
 * ac-map hrefs are authored relative to the run dir `<ts>/`:
 *   - `../acceptance/x`, `../screenshots/x`, `../evidence/x` — STORY-LEVEL
 *     artifacts that physically live at the story root (one level above the run
 *     dir). From the story root these are reached directly → strip the `../`.
 *   - `screenshots/x`, `evidence/x` (no `../`) — RUN-DIR-LOCAL artifacts under
 *     `<ts>/`. From the story root the live run dir is the `latest/` symlink →
 *     prefix with `latest/`.
 *
 * Absolute URLs, `/`-rooted paths, and hrefs already rooted at `latest/` are
 * left untouched. This is applied ONLY when building the story-page view-model
 * — the attest report (rendered at `<ts>/`) keeps its `../`-based hrefs, which
 * are correct there.
 */
export function rebaseEvidenceHrefToStoryRoot(href: string): string {
  const h = href.trim();
  if (h === "") return h;
  // Off-tree refs the page should never rewrite.
  if (/^[a-z]+:/i.test(h) || h.startsWith("/") || h.startsWith("#")) return h;
  // Already story-root-correct (on-disk hrefs minted by the collector).
  if (h.startsWith("latest/")) return h;
  // STORY-LEVEL: `../foo` (run-dir-relative to a sibling of `<ts>/`) → `foo`.
  if (h.startsWith("../")) {
    let rest = h.slice(3);
    // Defensively collapse any further `../` (none expected) so we never keep
    // an out-of-root segment on the story page.
    while (rest.startsWith("../")) rest = rest.slice(3);
    return rest;
  }
  // RUN-DIR-LOCAL: a bare `evidence/x` / `screenshots/x` lives under `<ts>/`;
  // reach the live run dir from the story root via the `latest/` symlink.
  return `latest/${h}`;
}

/** FIX-282 — apply {@link rebaseEvidenceHrefToStoryRoot} across a parsed
 *  ac-map evidence list when rendering the STORY PAGE. */
export function rebaseAcEvidenceToStoryRoot(ev: AcEvidence[]): AcEvidence[] {
  return ev.map((e) => (e.href !== undefined ? { ...e, href: rebaseEvidenceHrefToStoryRoot(e.href) } : e));
}

/** FIX-285 — text evidence is useful only when visible in the AC block. Read
 * story-root-relative text refs from the card folder and keep missing/unreadable
 * files as an honest empty state. Off-tree refs are not fetched. */
function hydrateTextEvidence(storyDir: string, ev: AcEvidence[]): AcEvidence[] {
  return ev.map((e) => {
    if (e.kind !== "text" || e.href === undefined) return e;
    if (/^[a-z]+:/i.test(e.href) || e.href.startsWith("/") || e.href.startsWith("#")) return { ...e, textError: "missing" };
    const root = resolvePath(storyDir);
    const target = resolvePath(storyDir, e.href);
    if (target !== root && !target.startsWith(`${root}${sep}`)) return { ...e, textError: "missing" };
    try {
      return { ...e, textContent: readFile(target) };
    } catch {
      return { ...e, textError: "missing" };
    }
  });
}

// Thin fs/git seams (kept local so the renderer stays pure above).
function readFile(p: string): string {
  return readFileSync(p, "utf8");
}
function statDir(p: string): boolean {
  return statSync(p).isFile();
}
function execGit(cwd: string, args: string[]): string {
  // FIX-327: ignore git's stderr. In a non-git dir (a test fixture's temp dir,
  // or a project that gitignores .roll) git prints "fatal: not a git repository"
  // to stderr. The caller already treats a throw as "no facts" (returns null),
  // but the leaked stderr polluted captured test output that agents attach as
  // inline AC evidence — a passing dossier run showed 52 scary "fatal:" lines.
  //
  // FIX-349: raise maxBuffer well above execFileSync's 1MB default. The full
  // `git log origin/main --name-only --pretty=...%B` scan exceeds 1MB once a
  // repo accrues enough history (this repo's own output is ~1.18MB), which made
  // execFileSync throw ENOBUFS → collectGitDossierFacts caught it and returned
  // null → every git-facts-dependent feature (the #loop merge-truth reconcile)
  // silently no-op'd. Test fixtures had <1MB logs so the gap stayed invisible.
  return execFileSync("git", args, {
    cwd,
    encoding: "utf8",
    timeout: 10_000,
    stdio: ["ignore", "pipe", "ignore"],
    maxBuffer: 256 * 1024 * 1024,
  });
}
